#[derive(Debug, Clone, Serialize)]
pub struct ResumeEvalCaseReport {
    pub session_id: Option<String>,
    pub task_identification: f64,
    pub reading_identification: f64,
    pub resume_target: f64,
    pub why_explanation: f64,
    pub distraction_handling: f64,
    pub hallucination_control: f64,
    pub warnings_count: usize,
    pub unknown_transition_count: usize,
    pub redacted_frame_handling_ok: bool,
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct ScreenCapturePermissionIdentity {
    pub executable_path: String,
    pub executable_name: Option<String>,
    pub bundle_identifier: Option<String>,
    pub bundle_path: Option<String>,
    pub signing_identifier: Option<String>,
    pub team_identifier: Option<String>,
    pub designated_requirement: Option<String>,
    pub cdhash: Option<String>,
    pub signature_kind: String,
    pub request_scope_key: String,
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct ScreenCapturePermissionStatus {
    pub state: String,
    pub granted: bool,
    pub can_request: bool,
    pub request_attempted: bool,
    pub restart_required: bool,
    pub message: String,
    pub settings_hint: Option<String>,
    pub identity: ScreenCapturePermissionIdentity,
}

struct CaptureEventSource {
    child: Option<Child>,
    reader: Option<JoinHandle<()>>,
    pipeline: Arc<event_pipeline::EventPipeline>,
}

fn screen_capture_permission_presentation(
    supported: bool,
    granted: bool,
    request_attempted: bool,
    identity: ScreenCapturePermissionIdentity,
) -> ScreenCapturePermissionStatus {
    if !supported {
        return ScreenCapturePermissionStatus {
            state: "unsupported".into(),
            granted: false,
            can_request: false,
            request_attempted,
            restart_required: false,
            message: "Screen capture is only available in the macOS desktop app.".into(),
            settings_hint: None,
            identity,
        };
    }
    if granted {
        return ScreenCapturePermissionStatus {
            state: "granted".into(),
            granted: true,
            can_request: false,
            request_attempted,
            restart_required: false,
            message: "Screen access is ready for this running Smalltalk app.".into(),
            settings_hint: None,
            identity,
        };
    }
    if request_attempted {
        return ScreenCapturePermissionStatus {
            state: "restart_required".into(),
            granted: false,
            can_request: false,
            request_attempted: true,
            restart_required: true,
            message: format!(
                "Screen access is still off for this Smalltalk app. Enable it in {SCREEN_CAPTURE_SETTINGS_HINT}, then quit and reopen Smalltalk."
            ),
            settings_hint: Some(SCREEN_CAPTURE_SETTINGS_HINT.into()),
            identity,
        };
    }
    ScreenCapturePermissionStatus {
        state: "request_required".into(),
        granted: false,
        can_request: true,
        request_attempted: false,
        restart_required: false,
        message: "Smalltalk needs screen access before local memory can start. Choose Allow screen access once; macOS will show the permission prompt.".into(),
        settings_hint: Some(SCREEN_CAPTURE_SETTINGS_HINT.into()),
        identity,
    }
}

fn screen_capture_permission_start_error(status: &ScreenCapturePermissionStatus) -> String {
    format!(
        "screen_capture_permission_{}: {}",
        status.state, status.message
    )
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
struct CodeSigningIdentity {
    signing_identifier: Option<String>,
    team_identifier: Option<String>,
    designated_requirement: Option<String>,
    cdhash: Option<String>,
    signature_kind: String,
}

fn parse_code_signing_identity(output: &str) -> CodeSigningIdentity {
    let mut identity = CodeSigningIdentity::default();
    for line in output.lines().map(str::trim) {
        if let Some(value) = line.strip_prefix("Identifier=") {
            identity.signing_identifier = Some(value.trim().to_string());
        } else if let Some(value) = line.strip_prefix("TeamIdentifier=") {
            let value = value.trim();
            if !value.is_empty() && value != "not set" {
                identity.team_identifier = Some(value.to_string());
            }
        } else if let Some(value) = line.strip_prefix("CDHash=") {
            identity.cdhash = Some(value.trim().to_string());
        } else if let Some(value) = line.strip_prefix("Signature=") {
            identity.signature_kind = value.trim().to_ascii_lowercase();
        } else if let Some(value) = line.strip_prefix("# designated =>") {
            identity.designated_requirement = Some(value.trim().to_string());
        }
    }
    if identity.signature_kind.is_empty() {
        identity.signature_kind = "unsigned_or_unknown".into();
    }
    identity
}

fn code_signing_identity(executable: Option<&Path>) -> CodeSigningIdentity {
    let Some(executable) = executable else {
        return CodeSigningIdentity {
            signature_kind: "unknown_executable".into(),
            ..Default::default()
        };
    };
    let Ok(output) = Command::new("/usr/bin/codesign")
        .args(["-d", "-r-", "--verbose=4"])
        .arg(executable)
        .output()
    else {
        return CodeSigningIdentity {
            signature_kind: "codesign_unavailable".into(),
            ..Default::default()
        };
    };
    let combined = format!(
        "{}\n{}",
        String::from_utf8_lossy(&output.stdout),
        String::from_utf8_lossy(&output.stderr)
    );
    parse_code_signing_identity(&combined)
}

fn permission_request_scope_key(
    executable: Option<&Path>,
    signing: &CodeSigningIdentity,
) -> String {
    // A certificate-backed designated requirement is stable across signed app
    // updates. An ad-hoc designated requirement contains its CDHash, so a new
    // ad-hoc build receives a new request scope instead of inheriting a stale
    // denial marker from an older binary.
    let material = signing
        .designated_requirement
        .as_ref()
        .map(|requirement| format!("designated_requirement:{requirement}"))
        .unwrap_or_else(|| {
            let metadata = executable.and_then(|path| fs::metadata(path).ok());
            let modified = metadata
                .as_ref()
                .and_then(|metadata| metadata.modified().ok())
                .and_then(|value| value.duration_since(UNIX_EPOCH).ok())
                .map(|value| value.as_nanos())
                .unwrap_or_default();
            format!(
                "unsigned:{}:{}:{modified}",
                executable
                    .map(|path| path.to_string_lossy())
                    .unwrap_or_default(),
                metadata
                    .as_ref()
                    .map(|value| value.len())
                    .unwrap_or_default(),
            )
        });
    format!(
        "{SCREEN_CAPTURE_PERMISSION_REQUESTED_AT_KEY_PREFIX}:{}",
        stable_hash_bytes(material.as_bytes())
    )
}

#[cfg(target_os = "macos")]
fn running_screen_capture_identity() -> ScreenCapturePermissionIdentity {
    use core_foundation::base::TCFType;
    use core_foundation::bundle::{CFBundle, CFBundleGetIdentifier};
    use core_foundation::string::CFString;

    SCREEN_CAPTURE_IDENTITY
        .get_or_init(|| {
            let executable = std::env::current_exe().ok();
            let signing = code_signing_identity(executable.as_deref());
            let bundle = CFBundle::main_bundle();
            let bundle_identifier = unsafe {
                let identifier = CFBundleGetIdentifier(bundle.as_concrete_TypeRef());
                (!identifier.is_null())
                    .then(|| CFString::wrap_under_get_rule(identifier).to_string())
            };
            ScreenCapturePermissionIdentity {
                executable_path: executable
                    .as_ref()
                    .map(|path| path.to_string_lossy().into_owned())
                    .unwrap_or_else(|| "unknown".into()),
                executable_name: executable
                    .as_ref()
                    .and_then(|path| path.file_name())
                    .map(|name| name.to_string_lossy().into_owned()),
                bundle_identifier,
                bundle_path: bundle
                    .path()
                    .map(|path| path.to_string_lossy().into_owned()),
                signing_identifier: signing.signing_identifier.clone(),
                team_identifier: signing.team_identifier.clone(),
                designated_requirement: signing.designated_requirement.clone(),
                cdhash: signing.cdhash.clone(),
                signature_kind: signing.signature_kind.clone(),
                request_scope_key: permission_request_scope_key(executable.as_deref(), &signing),
            }
        })
        .clone()
}

#[cfg(not(target_os = "macos"))]
fn running_screen_capture_identity() -> ScreenCapturePermissionIdentity {
    SCREEN_CAPTURE_IDENTITY
        .get_or_init(|| {
            let executable = std::env::current_exe().ok();
            let signing = code_signing_identity(executable.as_deref());
            ScreenCapturePermissionIdentity {
                executable_path: executable
                    .as_ref()
                    .map(|path| path.to_string_lossy().into_owned())
                    .unwrap_or_else(|| "unknown".into()),
                executable_name: executable
                    .as_ref()
                    .and_then(|path| path.file_name())
                    .map(|name| name.to_string_lossy().into_owned()),
                bundle_identifier: None,
                bundle_path: None,
                signing_identifier: signing.signing_identifier.clone(),
                team_identifier: signing.team_identifier.clone(),
                designated_requirement: signing.designated_requirement.clone(),
                cdhash: signing.cdhash.clone(),
                signature_kind: signing.signature_kind.clone(),
                request_scope_key: permission_request_scope_key(executable.as_deref(), &signing),
            }
        })
        .clone()
}

fn screen_capture_permission_was_requested(
    app: &AppHandle,
    identity: &ScreenCapturePermissionIdentity,
) -> bool {
    open_readonly_db(app)
        .ok()
        .and_then(|conn| maintenance_value(&conn, &identity.request_scope_key).ok())
        .flatten()
        .is_some()
}

fn claim_screen_capture_permission_request(conn: &Connection, key: &str) -> Result<bool, String> {
    conn.execute(
        "INSERT OR IGNORE INTO local_memory_maintenance (key, value, updated_at_ms)
         VALUES (?1, ?2, ?2)",
        params![key, now_millis()],
    )
    .map(|changed| changed == 1)
    .map_err(to_string)
}

fn permission_request_markers(conn: &Connection) -> Result<Vec<(String, String, i64)>, String> {
    if !table_exists_in_capture(conn, "local_memory_maintenance")? {
        return Ok(Vec::new());
    }
    let pattern = format!("{SCREEN_CAPTURE_PERMISSION_REQUESTED_AT_KEY_PREFIX}:%");
    let mut statement = conn
        .prepare(
            "SELECT key, value, updated_at_ms
             FROM local_memory_maintenance
             WHERE key LIKE ?1
             ORDER BY key ASC",
        )
        .map_err(to_string)?;
    let markers = statement
        .query_map(params![pattern], |row| {
            Ok((row.get(0)?, row.get(1)?, row.get(2)?))
        })
        .map_err(to_string)?
        .collect::<Result<Vec<_>, _>>()
        .map_err(to_string)?;
    Ok(markers)
}

fn restore_permission_request_markers(
    conn: &Connection,
    markers: &[(String, String, i64)],
) -> Result<(), String> {
    for (key, value, updated_at_ms) in markers {
        conn.execute(
            "INSERT OR REPLACE INTO local_memory_maintenance (key, value, updated_at_ms)
             VALUES (?1, ?2, ?3)",
            params![key, value, updated_at_ms],
        )
        .map_err(to_string)?;
    }
    Ok(())
}

fn screen_capture_permission_status(
    app: &AppHandle,
) -> Result<ScreenCapturePermissionStatus, String> {
    let identity = running_screen_capture_identity();
    let request_attempted = screen_capture_permission_was_requested(app, &identity);
    #[cfg(target_os = "macos")]
    {
        use core_graphics::access::ScreenCaptureAccess;
        return Ok(screen_capture_permission_presentation(
            true,
            ScreenCaptureAccess.preflight(),
            request_attempted,
            identity,
        ));
    }
    #[cfg(not(target_os = "macos"))]
    {
        Ok(screen_capture_permission_presentation(
            false,
            false,
            request_attempted,
            identity,
        ))
    }
}

#[tauri::command]
pub fn get_screen_capture_permission_status(
    app: AppHandle,
) -> Result<ScreenCapturePermissionStatus, String> {
    screen_capture_permission_status(&app)
}

#[tauri::command]
pub fn request_screen_capture_permission(
    app: AppHandle,
) -> Result<ScreenCapturePermissionStatus, String> {
    ensure_db(&app)?;
    let current = screen_capture_permission_status(&app)?;
    if current.granted || !current.can_request {
        return Ok(current);
    }

    // Persist before invoking the operating-system request. Even if the app is
    // interrupted while macOS presents its prompt, another click will report
    // the restart/settings instructions instead of repeatedly reopening it.
    let conn = open_db(&app)?;
    let claimed =
        claim_screen_capture_permission_request(&conn, &current.identity.request_scope_key)?;
    drop(conn);
    if !claimed {
        return screen_capture_permission_status(&app);
    }

    #[cfg(target_os = "macos")]
    {
        use core_graphics::access::ScreenCaptureAccess;
        let granted = ScreenCaptureAccess.request();
        return Ok(screen_capture_permission_presentation(
            true,
            granted || ScreenCaptureAccess.preflight(),
            true,
            running_screen_capture_identity(),
        ));
    }
    #[cfg(not(target_os = "macos"))]
    {
        screen_capture_permission_status(&app)
    }
}

impl SemanticFingerprint {
    fn from_context(context: &AccessibilityContext) -> Self {
        Self {
            app_name: context.app_name.clone(),
            window_name: context.window_name.clone(),
            browser_url: context.browser_url.clone(),
            document_path: context.document_path.clone(),
            text_hash: non_empty(context.text.clone())
                .map(|text| stable_hash_bytes(text.as_bytes())),
        }
    }
}

#[tauri::command]
pub fn start_capture(app: AppHandle, state: State<CaptureState>) -> Result<CaptureStatus, String> {
    start_capture_impl(app, state.inner())
}

fn start_capture_impl(app: AppHandle, state: &CaptureState) -> Result<CaptureStatus, String> {
    ensure_db(&app)?;

    let generation = {
        let mut runtime = lock_runtime(state)?;
        if runtime.phase.owns_worker() || runtime.worker.is_some() {
            if runtime.phase == CaptureRuntimePhase::Stopping {
                return Err(
                    "capture is stopping; wait for cleanup before starting again".to_string(),
                );
            }
            drop(runtime);
            let status = capture_status_snapshot_inner(&app, &state.inner)?;
            crate::session_island::update_session_island_from_status(
                &status,
                crate::session_island::SessionIslandState::RecordingCompact,
            );
            return Ok(status);
        }
        runtime.worker_generation = runtime.worker_generation.saturating_add(1);
        runtime.phase = CaptureRuntimePhase::Starting;
        runtime.last_error = None;
        runtime.worker_generation
    };

    if let Err(error) = recover_interrupted_capture_triggers(&open_db(&app)?, now_millis()) {
        fail_capture_start(state, generation, &error);
        return Err(error);
    }

    let permission = match screen_capture_permission_status(&app) {
        Ok(permission) => permission,
        Err(error) => {
            fail_capture_start(state, generation, &error);
            return Err(error);
        }
    };
    if !permission.granted {
        let error = screen_capture_permission_start_error(&permission);
        fail_capture_start(state, generation, &error);
        return Err(error);
    }

    crate::session_island::update_session_island(
        crate::session_island::SessionIslandSnapshot::starting(),
    );
    crate::session_island::show_session_island();

    let session = match create_capture_session(&app) {
        Ok(session) => session,
        Err(error) => {
            fail_capture_start(state, generation, &error);
            return Err(error);
        }
    };
    let session_id = session.id.clone();
    provider_health::with_registry(provider_health::ProviderHealthRegistry::reset_for_new_session);

    let stop_signal = CancellationToken::default();
    let thread_stop = stop_signal.clone();
    let thread_app = app.clone();
    let thread_state = state.inner.clone();
    let thread_session_id = session_id.clone();
    let completion = Arc::new(WorkerCompletion::default());
    let thread_completion = completion.clone();
    let (start_gate_tx, start_gate_rx) = mpsc::sync_channel::<()>(0);
    let worker = match thread::Builder::new()
        .name(format!("capture-worker-{generation}"))
        .spawn(move || {
            if start_gate_rx.recv().is_err() {
                return;
            }
            run_capture_worker(
                thread_app,
                thread_state,
                thread_stop,
                thread_session_id,
                generation,
                thread_completion,
            );
        }) {
        Ok(worker) => worker,
        Err(error) => {
            let message = format!("failed to create capture worker: {error}");
            let _ = finalize_capture_session(&app, &session_id, "failed");
            fail_capture_start(state, generation, &message);
            return Err(message);
        }
    };

    {
        let mut runtime = lock_runtime(state)?;
        if runtime.worker_generation != generation || runtime.phase != CaptureRuntimePhase::Starting
        {
            stop_signal.cancel();
            drop(start_gate_tx);
            drop(runtime);
            let _ = worker.join();
            let _ = finalize_capture_session(&app, &session_id, "failed");
            return Err("capture start was superseded before worker registration".to_string());
        }
        runtime.started_at = Some(session.started_at);
        runtime.last_error = None;
        runtime.skipped_samples = 0;
        runtime.last_skipped_at = None;
        runtime.active_session_id = Some(session_id.clone());
        runtime.last_session = Some(session);
        runtime.last_export = None;
        runtime.stop_signal = Some(stop_signal);
        runtime.worker_completion = Some(completion);
        runtime.worker = Some(worker);
    }
    if start_gate_tx.send(()).is_err() {
        let message = "capture worker failed before startup completed".to_string();
        let worker = {
            let mut runtime = lock_runtime(state)?;
            runtime.phase = CaptureRuntimePhase::Failed;
            runtime.started_at = None;
            runtime.last_error = Some(message.clone());
            runtime.active_session_id = None;
            runtime.stop_signal = None;
            runtime.worker_completion = None;
            runtime.worker.take()
        };
        if let Some(worker) = worker {
            let _ = worker.join();
        }
        if let Ok(finalized) = finalize_capture_session(&app, &session_id, "failed") {
            if let Ok(mut runtime) = lock_runtime(state) {
                runtime.last_session = Some(finalized);
            }
        }
        crate::session_island::update_session_island(
            crate::session_island::SessionIslandSnapshot::error(message.clone()),
        );
        return Err(message);
    }
    {
        let mut runtime = lock_runtime(state)?;
        if runtime.worker_generation == generation && runtime.phase == CaptureRuntimePhase::Starting
        {
            runtime.phase = CaptureRuntimePhase::Running;
        }
    }

    let status = capture_status_snapshot_inner(&app, &state.inner)?;
    crate::session_island::update_session_island_from_status(
        &status,
        crate::session_island::SessionIslandState::RecordingCompact,
    );
    Ok(status)
}

#[tauri::command]
pub async fn stop_capture(
    app: AppHandle,
    state: State<'_, CaptureState>,
) -> Result<StopCaptureOutput, String> {
    let capture_state = state.inner().clone();
    tauri::async_runtime::spawn_blocking(move || stop_capture_impl(app, &capture_state))
        .await
        .map_err(|error| format!("capture Stop task failed: {error}"))?
}

pub(crate) fn stop_capture_impl(
    app: AppHandle,
    state: &CaptureState,
) -> Result<StopCaptureOutput, String> {
    if let Ok(status) = capture_status_snapshot_inner(&app, &state.inner) {
        crate::session_island::update_session_island_from_status(
            &status,
            crate::session_island::SessionIslandState::Processing,
        );
    }

    let session_id = {
        let runtime = lock_runtime(state)?;
        runtime.active_session_id.clone()
    };

    stop_runtime(state)?;

    if let Ok(conn) = open_db(&app) {
        let _ = maybe_run_runtime_maintenance(&conn, true);
    }

    let mut stopped_session = None;
    let mut resume_query = None;
    if let Some(session_id) = session_id {
        let session = load_capture_session_for_status(&open_db(&app)?, &session_id)?;
        {
            let mut runtime = lock_runtime(state)?;
            runtime.active_session_id = None;
            runtime.last_session = Some(session.clone());
            runtime.last_export = None;
        }
        stopped_session = Some(session.clone());

        let latest_frame_id = {
            let conn = open_db(&app)?;
            latest_frame_id_for_session_from_conn(&conn, &session.id)
                .ok()
                .flatten()
                .and_then(|id| id.parse::<i64>().ok())
        };
        resume_query = {
            let conn = open_db(&app)?;
            match build_resume_query_bundle_from_conn(
                &conn,
                &project_resume_query_root()?,
                Some(ResumeQueryBundleInput {
                    session_id: Some(session.id.clone()),
                    current_frame_id: latest_frame_id,
                    lookback_minutes: None,
                    max_episode_cards: None,
                    max_images: None,
                    max_json_chars: None,
                    max_keyframes: Some(8),
                    include_images: Some(true),
                }),
            ) {
                Ok(query) => Some(query),
                Err(error) => {
                    if is_thin_resume_trail_error(&error) {
                        None
                    } else {
                        let message = format!(
                            "Stopped capture, but failed to save resume trail: {}",
                            error
                        );
                        update_error(&state.inner, message.clone());
                        crate::session_island::update_session_island(
                            crate::session_island::SessionIslandSnapshot::error(message.clone()),
                        );
                        return Err(message);
                    }
                }
            }
        };
    }

    let status = capture_status_snapshot_inner(&app, &state.inner)?;
    crate::session_island::update_session_island_from_status(
        &status,
        crate::session_island::SessionIslandState::StoppedToast,
    );
    crate::session_island::return_to_ready_after_stop(app.clone());
    let preview = stopped_session.as_ref().map(|session| {
        serde_json::json!({
            "schema": "smalltalk.capture_session.stop_preview.v1",
            "session": session,
            "resumeQuery": resume_query.as_ref().map(|query| serde_json::json!({
                "schema": query.bundle.schema,
                "outputDir": query.output_dir,
                "bundlePath": query.bundle_path,
                "byteSize": query.byte_size,
                "jsonCharCount": query.json_char_count,
                "imageCount": query.image_count,
                "episodeCount": query.bundle.candidate_episodes.len(),
                "candidate": query.bundle.resume_candidate,
                "missingEvidence": query.bundle.missing_evidence,
            })),
        })
    });

    Ok(StopCaptureOutput {
        status,
        session: stopped_session,
        export: None,
        resume_query,
        preview,
    })
}

fn is_thin_resume_trail_error(error: &str) -> bool {
    error.contains("has no non-internal frames to summarize")
        || error.contains("has no model-safe frames after privacy filtering")
}

#[tauri::command]
pub fn capture_once(app: AppHandle, state: State<CaptureState>) -> Result<CaptureFrame, String> {
    let (session_id, cancellation) = {
        let runtime = lock_runtime(state.inner())?;
        let session_id = runtime
            .active_session_id
            .clone()
            .ok_or_else(|| "start a session before capturing a manual frame".to_string())?;
        (session_id, runtime.stop_signal.clone())
    };
    let pre_frame_id = latest_frame_id_for_session(&app, &session_id)
        .ok()
        .flatten();
    let trigger_id =
        insert_system_capture_trigger(&app, &session_id, "manual", pre_frame_id.clone(), false)?;
    let outcome = capture_frame(
        &app,
        &session_id,
        "manual",
        false,
        None,
        None,
        None,
        None,
        cancellation.as_ref(),
        Some(&trigger_id),
        pre_frame_id.as_deref(),
        None,
    )?;
    let frame = outcome
        .frame
        .ok_or_else(|| "capture was skipped before a frame was stored".to_string())?;
    let _ = finalize_capture_trigger_by_id(&app, &trigger_id, true);
    {
        let mut runtime = lock_runtime(state.inner())?;
        runtime.last_error = None;
        runtime.last_frame = Some(frame.clone());
    }

    if let Ok(status) = capture_status_snapshot(&app, &state) {
        let _ = app.emit("capture-status", status.clone());
        crate::session_island::update_session_island_from_status(
            &status,
            crate::session_island::SessionIslandState::RecordingCompact,
        );
    }
    Ok(frame)
}

#[tauri::command]
