#[tauri::command]
pub fn search_content_units(
    app: AppHandle,
    query: String,
    limit: Option<u32>,
) -> Result<Vec<ContentUnitSummary>, String> {
    let conn = open_db(&app)?;
    let like = format!("%{}%", query.trim());
    let limit = limit.unwrap_or(50).clamp(1, 100);
    let mut stmt = conn
        .prepare(
            "SELECT id, source, unit_type, semantic_role, text, bounds_x, bounds_y,
                    bounds_w, bounds_h, confidence, source_scope, ownership_kind,
                    ownership_confidence, active_artifact_match_confidence, owner_window_id,
                    owner_bundle_id, quality_flags_json
             FROM content_units
             WHERE text LIKE ?1
             ORDER BY created_at_ms DESC
             LIMIT ?2",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map(params![like, limit], content_unit_from_row)
        .map_err(to_string)?;
    rows.collect::<Result<Vec<_>, _>>().map_err(to_string)
}

#[tauri::command]
pub fn add_exclusion_rule(
    app: AppHandle,
    rule: ExclusionRuleInput,
) -> Result<ExclusionRule, String> {
    validate_exclusion_rule(&rule.rule_type, &rule.pattern)?;
    if !matches!(
        rule.action.as_str(),
        "skip_capture" | "store_redacted" | "never_send_to_ai"
    ) {
        return Err("unsupported privacy exclusion action".to_string());
    }
    let conn = open_db(&app)?;
    let created_at_ms = now_millis();
    let id = next_id("rule");
    let enabled = rule.enabled.unwrap_or(true);
    conn.execute(
        "INSERT INTO exclusion_rules (
            id, rule_type, pattern, action, enabled, origin, created_at_ms
         ) VALUES (?1, ?2, ?3, ?4, ?5, 'user', ?6)",
        params![
            id,
            rule.rule_type,
            rule.pattern,
            rule.action,
            bool_to_i64(enabled),
            created_at_ms,
        ],
    )
    .map_err(to_string)?;
    Ok(ExclusionRule {
        id,
        rule_type: rule.rule_type,
        pattern: rule.pattern,
        action: rule.action,
        enabled,
        origin: "user".to_string(),
        created_at_ms,
    })
}

#[tauri::command]
