const MANUAL_CONTINUE_EVENT_RECENCY_MS: i64 = 60_000;
const MANUAL_CONTINUE_FRAME_REUSE_RECENCY_MS: i64 = 5_000;

#[derive(Debug, Clone)]
struct ManualContinueExternalEvent {
    ts_ms: i64,
    app_pid: Option<i64>,
    app_bundle_id: Option<String>,
    app_name: Option<String>,
    window_id: Option<i64>,
    window_title: Option<String>,
}

#[derive(Debug, Clone)]
struct ManualContinueCaptureExpectation {
    app_bundle_id: Option<String>,
    app_name: Option<String>,
    window_id: Option<i64>,
}

#[derive(Debug, Clone)]
struct ManualContinueCaptureFailure {
    trigger_id: Option<String>,
    public_reason: String,
    trigger_reason: String,
}

impl From<String> for ManualContinueCaptureFailure {
    fn from(reason: String) -> Self {
        Self {
            trigger_id: None,
            public_reason: reason.clone(),
            trigger_reason: reason,
        }
    }
}

fn latest_manual_continue_external_event(
    conn: &Connection,
    session_id: &str,
    pressed_at_ms: i64,
) -> Result<Option<ManualContinueExternalEvent>, String> {
    conn.query_row(
        "SELECT ts_ms, app_pid, app_bundle_id, app_name, window_id, window_title
         FROM ui_events
         WHERE session_id = ?1
           AND event_type IN ('app_switch','window_focus','click','scroll','key_down','clipboard')
           AND COALESCE(app_bundle_id, '') != ?2
           AND lower(COALESCE(app_name, '')) NOT IN (
             'smalltalk', 'system settings', 'usernotificationcenter',
             'universalaccessauthwarn'
           )
           AND ts_ms >= ?3
         ORDER BY ts_ms DESC, created_at_ms DESC
         LIMIT 1",
        params![
            session_id,
            SMALLTALK_BUNDLE_ID,
            pressed_at_ms.saturating_sub(MANUAL_CONTINUE_EVENT_RECENCY_MS)
        ],
        |row| {
            Ok(ManualContinueExternalEvent {
                ts_ms: row.get(0)?,
                app_pid: row.get(1)?,
                app_bundle_id: row.get(2)?,
                app_name: row.get(3)?,
                window_id: row.get(4)?,
                window_title: row.get(5)?,
            })
        },
    )
    .optional()
    .map_err(to_string)
}

fn privacy_status_allows_manual_continue_frame(status: Option<&str>) -> bool {
    let status = status.unwrap_or("normal").trim().to_ascii_lowercase();
    !matches!(
        status.as_str(),
        "private" | "excluded" | "blocked" | "sensitive"
    ) && !status.contains("diagnostic_self")
        && !status.contains("identity_conflict")
}

fn normalized_manual_continue_window_title(value: &str, app_name: Option<&str>) -> String {
    let clean = |text: &str| {
        text.chars()
            .filter(|character| {
                !matches!(
                    character,
                    '\u{200e}'
                        | '\u{200f}'
                        | '\u{202a}'
                        | '\u{202b}'
                        | '\u{202c}'
                        | '\u{202d}'
                        | '\u{202e}'
                        | '\u{2066}'
                        | '\u{2067}'
                        | '\u{2068}'
                        | '\u{2069}'
                )
            })
            .collect::<String>()
            .trim()
            .to_lowercase()
    };
    let mut title = clean(value);
    let Some(app_name) = app_name.map(clean).filter(|value| !value.is_empty()) else {
        return title;
    };
    for separator in [" - ", " — ", " – ", " | "] {
        let suffix = format!("{separator}{app_name}");
        if title.ends_with(&suffix) {
            title.truncate(title.len().saturating_sub(suffix.len()));
            return title.trim().to_string();
        }
    }
    title
}

fn manual_continue_window_titles_match(
    expected: &str,
    actual: &str,
    app_name: Option<&str>,
) -> bool {
    normalized_manual_continue_window_title(expected, app_name)
        == normalized_manual_continue_window_title(actual, app_name)
}

fn manual_continue_anchor_since(
    conn: &Connection,
    session_id: &str,
    event: &ManualContinueExternalEvent,
    minimum_captured_at: i64,
    now_ms: i64,
) -> Result<Option<String>, String> {
    let mut stmt = conn
        .prepare(
            "SELECT CAST(id AS TEXT), app_bundle_id, app_name, window_id, window_name,
                    privacy_status, active_window_crop_path, full_screenshot_path
             FROM frames
             WHERE session_id = ?1 AND captured_at BETWEEN ?2 AND ?3
             ORDER BY captured_at DESC, id DESC
             LIMIT 24",
        )
        .map_err(to_string)?;
    let rows = stmt
        .query_map(params![session_id, minimum_captured_at, now_ms], |row| {
            Ok((
                row.get::<_, String>(0)?,
                row.get::<_, Option<String>>(1)?,
                row.get::<_, Option<String>>(2)?,
                row.get::<_, Option<i64>>(3)?,
                row.get::<_, Option<String>>(4)?,
                row.get::<_, Option<String>>(5)?,
                row.get::<_, Option<String>>(6)?,
                row.get::<_, Option<String>>(7)?,
            ))
        })
        .map_err(to_string)?
        .collect::<Result<Vec<_>, _>>()
        .map_err(to_string)?;
    Ok(rows.into_iter().find_map(
        |(frame_id, bundle_id, app_name, window_id, window_name, privacy, crop, full)| {
            let is_smalltalk = bundle_id.as_deref() == Some(SMALLTALK_BUNDLE_ID)
                || app_name
                    .as_deref()
                    .is_some_and(|name| name.eq_ignore_ascii_case("smalltalk"));
            let has_readable_asset = crop
                .as_deref()
                .is_some_and(|value| manual_continue_asset_is_decodable(Path::new(value)))
                || full
                    .as_deref()
                    .is_some_and(|value| manual_continue_asset_is_decodable(Path::new(value)));
            if is_smalltalk
                || !has_readable_asset
                || !privacy_status_allows_manual_continue_frame(privacy.as_deref())
            {
                return None;
            }
            let app_matches = match (event.app_bundle_id.as_deref(), bundle_id.as_deref()) {
                (Some(expected), Some(actual)) if !expected.trim().is_empty() => expected == actual,
                _ => match (event.app_name.as_deref(), app_name.as_deref()) {
                    (Some(expected), Some(actual)) => expected.eq_ignore_ascii_case(actual),
                    _ => false,
                },
            };
            let title_matches = match (
                event
                    .window_title
                    .as_deref()
                    .map(str::trim)
                    .filter(|value| !value.is_empty()),
                window_name
                    .as_deref()
                    .map(str::trim)
                    .filter(|value| !value.is_empty()),
            ) {
                (Some(expected), Some(actual)) => {
                    manual_continue_window_titles_match(expected, actual, event.app_name.as_deref())
                }
                _ => false,
            };
            let exact_window_matches = match (event.window_id, window_id) {
                (Some(expected), Some(actual)) if expected > 0 && actual > 0 => expected == actual,
                _ => title_matches,
            };
            (app_matches && exact_window_matches).then_some(frame_id)
        },
    ))
}

fn manual_continue_anchor_once(
    conn: &Connection,
    session_id: &str,
    event: Option<&ManualContinueExternalEvent>,
    now_ms: i64,
) -> Result<Option<String>, String> {
    let Some(event) = event else {
        return Ok(None);
    };
    let minimum_captured_at = event
        .ts_ms
        .max(now_ms.saturating_sub(MANUAL_CONTINUE_FRAME_REUSE_RECENCY_MS));
    manual_continue_anchor_since(conn, session_id, event, minimum_captured_at, now_ms)
}

fn recent_manual_continue_fallback_anchor(
    conn: &Connection,
    session_id: &str,
    event: &ManualContinueExternalEvent,
    boundary_started_at_ms: i64,
    now_ms: i64,
) -> Result<Option<String>, String> {
    let minimum_captured_at = event
        .ts_ms
        .max(boundary_started_at_ms.saturating_sub(MANUAL_CONTINUE_FRAME_REUSE_RECENCY_MS));
    manual_continue_anchor_since(conn, session_id, event, minimum_captured_at, now_ms)
}

fn manual_continue_asset_is_decodable(path: &Path) -> bool {
    let Ok(bytes) = fs::read(path) else {
        return false;
    };
    if jpeg_dimensions(&bytes).is_some() {
        return true;
    }
    const PNG_END: &[u8] = b"\0\0\0\0IEND\xaeB`\x82";
    if bytes.len() < 45
        || &bytes[..8] != b"\x89PNG\r\n\x1a\n"
        || &bytes[12..16] != b"IHDR"
        || !bytes.ends_with(PNG_END)
    {
        return false;
    }
    let width = u32::from_be_bytes(bytes[16..20].try_into().unwrap_or([0; 4]));
    let height = u32::from_be_bytes(bytes[20..24].try_into().unwrap_or([0; 4]));
    width > 0 && height > 0
}

fn record_manual_continue_frame_reuse(
    conn: &Connection,
    session_id: &str,
    frame_id: &str,
    reuse_source: &str,
    existing_trigger_id: Option<&str>,
    pre_frame_id: Option<&str>,
    capture_failure_reason: Option<&str>,
) -> Result<String, String> {
    let trigger_id = if let Some(trigger_id) = existing_trigger_id {
        trigger_id.to_string()
    } else {
        let trigger = PendingTrigger {
            id: next_id("trg"),
            capture_trigger: "manual_continue_boundary".to_string(),
            caused_by_event_ids: Vec::new(),
            caused_event_count: 0,
            omitted_event_count: 0,
            pre_frame_id: pre_frame_id.map(str::to_string),
            settle_delay_ms: 0,
            ready_at: Instant::now(),
        };
        insert_capture_trigger(
            conn,
            session_id,
            &trigger,
            now_millis(),
            false,
            "exact_frame_reuse",
        )?;
        trigger.id
    };
    let reuse_audit = serde_json::json!({
        "schema": "smalltalk.manual_continue_frame_reuse.v1",
        "reuse_source": reuse_source,
        "reused_frame_id": frame_id,
        "capture_failure_reason": capture_failure_reason,
        "requirements": [
            "same_session",
            "exact_app_and_window",
            "post_event",
            "privacy_eligible",
            "readable_asset"
        ]
    });
    let changed = conn
        .execute(
            "UPDATE capture_triggers
         SET status='captured', post_frame_id=?2, aggregation_json=?3,
             dedupe_policy='exact_frame_reuse', error=NULL
         WHERE id=?1",
            params![trigger_id, frame_id, reuse_audit.to_string()],
        )
        .map_err(to_string)?;
    if changed != 1 {
        return Err(format!(
            "manual_continue_frame_reuse_trigger_missing:{trigger_id}"
        ));
    }
    Ok(trigger_id)
}

fn manual_continue_capture_identity_matches(
    expected: &ManualContinueCaptureExpectation,
    capture: &ScreenshotCapture,
) -> bool {
    let is_smalltalk = capture.bundle_id.as_deref() == Some(SMALLTALK_BUNDLE_ID)
        || capture
            .owner_name
            .as_deref()
            .is_some_and(|name| name.eq_ignore_ascii_case("smalltalk"));
    if is_smalltalk {
        return false;
    }
    let window_matches = expected
        .window_id
        .map(|window_id| capture.window_id == Some(window_id))
        .unwrap_or(true);
    let app_matches = expected
        .app_bundle_id
        .as_deref()
        .filter(|bundle_id| !bundle_id.trim().is_empty())
        .map(|bundle_id| {
            capture.bundle_id.as_deref() == Some(bundle_id)
                || (capture.bundle_id.is_none()
                    && expected.app_name.as_deref().is_some_and(|expected_name| {
                        capture.owner_name.as_deref().is_some_and(|actual_name| {
                            expected_name.eq_ignore_ascii_case(actual_name)
                        })
                    }))
        })
        .unwrap_or_else(|| {
            expected.app_name.as_deref().is_none_or(|expected_name| {
                capture
                    .owner_name
                    .as_deref()
                    .is_some_and(|actual_name| expected_name.eq_ignore_ascii_case(actual_name))
            })
        });
    window_matches && app_matches
}

fn annotate_capture_with_window_owner(
    capture: &mut ScreenshotCapture,
    snapshot: Option<&WindowSnapshotPayload>,
) {
    let Some(window_id) = capture.window_id else {
        return;
    };
    let Some(window) = snapshot
        .into_iter()
        .flat_map(|snapshot| snapshot.windows.iter())
        .find(|window| window.cg_window_id == Some(window_id))
    else {
        return;
    };
    capture.bundle_id = window.bundle_id.clone();
    capture.owner_pid = window.owner_pid;
    capture.owner_name = window.owner_name.clone();
}

fn resolve_capture_window_id(
    context_window_id: Option<i64>,
    snapshot: Option<&WindowSnapshotPayload>,
    manual_external_target: bool,
) -> Option<i64> {
    if manual_external_target {
        context_window_id
    } else {
        context_window_id.or_else(|| snapshot.and_then(|snapshot| snapshot.active_window_id))
    }
}

fn resolve_manual_continue_window_id(
    event: &ManualContinueExternalEvent,
    snapshot: Option<&WindowSnapshotPayload>,
) -> Option<i64> {
    let expected_bundle = event
        .app_bundle_id
        .as_deref()
        .filter(|value| !value.trim().is_empty());
    let expected_title = event
        .window_title
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let expected_app = event
        .app_name
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let candidate_matches = |window: &WindowPayload| {
        let is_smalltalk = window.bundle_id.as_deref() == Some(SMALLTALK_BUNDLE_ID)
            || window
                .owner_name
                .as_deref()
                .is_some_and(|name| name.eq_ignore_ascii_case("smalltalk"));
        if is_smalltalk {
            return false;
        }
        let app_matches = expected_bundle
            .map(|bundle| window.bundle_id.as_deref() == Some(bundle))
            .unwrap_or_else(|| {
                expected_app.is_some_and(|app| {
                    window
                        .owner_name
                        .as_deref()
                        .is_some_and(|owner| owner.eq_ignore_ascii_case(app))
                })
            });
        let title_matches = expected_title
            .map(|title| {
                window.window_title.as_deref().is_some_and(|actual| {
                    manual_continue_window_titles_match(title, actual, expected_app)
                })
            })
            .unwrap_or(true);
        app_matches && title_matches
    };
    let snapshot = snapshot?;
    if let Some(window_id) = event.window_id.filter(|value| *value > 0) {
        return snapshot
            .windows
            .iter()
            .find(|window| window.cg_window_id == Some(window_id) && candidate_matches(window))
            .and_then(|window| window.cg_window_id);
    }
    let matches = snapshot
        .windows
        .iter()
        .filter(|window| window.is_onscreen.unwrap_or(false) && window.layer.unwrap_or(0) == 0)
        .filter(|window| candidate_matches(window))
        .filter_map(|window| window.cg_window_id.filter(|value| *value > 0))
        .collect::<Vec<_>>();
    match matches.as_slice() {
        [window_id] => Some(*window_id),
        _ => None,
    }
}

fn capture_manual_continue_external_frame(
    app: &AppHandle,
    session_id: &str,
    event: &ManualContinueExternalEvent,
) -> Result<String, ManualContinueCaptureFailure> {
    let expected_bundle = event
        .app_bundle_id
        .as_deref()
        .filter(|value| !value.trim().is_empty());
    if expected_bundle == Some(SMALLTALK_BUNDLE_ID)
        || event
            .app_name
            .as_deref()
            .is_some_and(|name| name.eq_ignore_ascii_case("smalltalk"))
    {
        return Err("manual_continue_external_surface_is_smalltalk"
            .to_string()
            .into());
    }
    let paths = capture_paths(app)?;
    let window_snapshot = collect_window_snapshot(&paths, WINDOW_SNAPSHOT_DEADLINE, None).ok();
    let target_window_id = resolve_manual_continue_window_id(event, window_snapshot.as_ref());
    if target_window_id.is_none() && expected_bundle.is_none() {
        return Err("manual_continue_external_surface_identity_missing"
            .to_string()
            .into());
    }

    let pre_frame_id = latest_frame_id_for_session(app, session_id).ok().flatten();
    let trigger_id = insert_system_capture_trigger(
        app,
        session_id,
        "manual_continue_boundary",
        pre_frame_id.clone(),
        false,
    )?;
    let context = AccessibilityContext {
        app_pid: event.app_pid,
        app_bundle_id: event.app_bundle_id.clone(),
        app_name: event.app_name.clone(),
        window_id: target_window_id,
        window_name: event.window_title.clone(),
        error: Some("manual_continue_targeted_external_capture".to_string()),
        ..AccessibilityContext::default()
    };
    let expectation = ManualContinueCaptureExpectation {
        app_bundle_id: event.app_bundle_id.clone(),
        app_name: event.app_name.clone(),
        window_id: target_window_id,
    };
    let outcome = match capture_frame(
        app,
        session_id,
        "manual_continue_boundary",
        false,
        None,
        None,
        Some(context),
        None,
        None,
        Some(&trigger_id),
        pre_frame_id.as_deref(),
        Some(&expectation),
    ) {
        Ok(outcome) => outcome,
        Err(error) => {
            let _ = mark_capture_trigger_failed(app, &trigger_id, &error);
            return Err(ManualContinueCaptureFailure {
                trigger_id: Some(trigger_id),
                public_reason: "manual_continue_external_window_capture_failed".to_string(),
                trigger_reason: error,
            });
        }
    };
    let Some(frame) = outcome.frame else {
        let reason = outcome
            .skip_reason
            .unwrap_or_else(|| "capture_not_stored".to_string());
        let _ = mark_capture_trigger_failed(app, &trigger_id, &reason);
        return Err(ManualContinueCaptureFailure {
            trigger_id: Some(trigger_id),
            public_reason: format!("manual_continue_external_window_{reason}"),
            trigger_reason: reason,
        });
    };
    if frame.captured_at < event.ts_ms {
        let _ = mark_capture_trigger_failed(app, &trigger_id, "captured_before_external_event");
        return Err(ManualContinueCaptureFailure {
            trigger_id: Some(trigger_id),
            public_reason: "manual_continue_external_window_not_post_event".to_string(),
            trigger_reason: "captured_before_external_event".to_string(),
        });
    }
    let _ = finalize_capture_trigger_by_id(app, &trigger_id, true);
    Ok(frame.id.to_string())
}

fn resolve_manual_continue_frame_without_held_connection(
    app: &AppHandle,
    session_id: &str,
) -> Result<String, String> {
    let pressed_at_ms = now_millis();
    let (event, existing_anchor, pre_frame_id) = {
        let conn = open_db(app)?;
        let event = latest_manual_continue_external_event(&conn, session_id, pressed_at_ms)?;
        let pre_frame_id = latest_frame_id_for_session_from_conn(&conn, session_id)?;
        let anchor = manual_continue_anchor_once(&conn, session_id, event.as_ref(), pressed_at_ms)?;
        if let Some(frame_id) = anchor.as_deref() {
            record_manual_continue_frame_reuse(
                &conn,
                session_id,
                frame_id,
                "pre_capture_exact_anchor",
                None,
                pre_frame_id.as_deref(),
                None,
            )?;
        }
        (event, anchor, pre_frame_id)
    };
    if let Some(frame_id) = existing_anchor {
        return Ok(frame_id);
    }
    let event = event.ok_or_else(|| "manual_continue_recent_external_event_missing".to_string())?;
    match capture_manual_continue_external_frame(app, session_id, &event) {
        Ok(frame_id) => Ok(frame_id),
        Err(capture_failure) => {
            // Reopen only after the capture wait. Another exact post-event
            // frame may have completed while the manual request was queued.
            let conn = open_db(app)?;
            if let Some(frame_id) = recent_manual_continue_fallback_anchor(
                &conn,
                session_id,
                &event,
                pressed_at_ms,
                now_millis(),
            )? {
                record_manual_continue_frame_reuse(
                    &conn,
                    session_id,
                    &frame_id,
                    "post_capture_failure_exact_anchor",
                    capture_failure.trigger_id.as_deref(),
                    pre_frame_id.as_deref(),
                    Some(&capture_failure.trigger_reason),
                )?;
                return Ok(frame_id);
            }
            Err(capture_failure.public_reason)
        }
    }
}

#[tauri::command]
pub fn get_continue_decision(
    app: AppHandle,
    input: Option<crate::continuation::ContinueDecisionRequest>,
) -> Result<crate::continuation::ContinueDecisionResult, String> {
    let mut request = input.unwrap_or_default();
    let trigger = request.request_trigger.as_deref().unwrap_or_else(|| {
        if request.island_source.is_some() {
            "island"
        } else {
            "startup"
        }
    });
    let work_class = match trigger {
        "manual" => crate::workload::WorkClass::ManualContinue,
        "background" | "startup" => crate::workload::WorkClass::BackgroundContinue,
        _ if request.island_source.is_some() => crate::workload::WorkClass::IslandRefresh,
        _ => crate::workload::WorkClass::BackgroundContinue,
    };
    request.manual_continue_started_at_ms = (trigger == "manual").then_some(now_millis());
    request.manual_continue_frame_id = None;
    request.manual_continue_preflight_failure = None;
    {
        let preflight_conn = open_db(&app)?;
        if request.session_id.is_none() {
            request.session_id = latest_session_id(&preflight_conn)?;
        }
    }
    if trigger == "manual" {
        match request.session_id.as_deref() {
            Some(session_id) => {
                match resolve_manual_continue_frame_without_held_connection(&app, session_id) {
                    Ok(frame_id) => request.manual_continue_frame_id = Some(frame_id),
                    Err(reason) => request.manual_continue_preflight_failure = Some(reason),
                }
            }
            None => {
                request.manual_continue_preflight_failure =
                    Some("manual_continue_session_scope_missing".to_string())
            }
        }
    }
    let material_watermark = {
        let conn = open_db(&app)?;
        crate::continuation::current_continue_evidence_watermark_hash(
            &conn,
            request.session_id.as_deref(),
        )?
    };
    // Screenshot capture must remain allowed while the preflight waits for the
    // exact persisted external frame. Only acquire the Continue permit after
    // that boundary is established or has failed closed.
    let continue_permit_timeout = if work_class == crate::workload::WorkClass::ManualContinue {
        MANUAL_CONTINUE_PERMIT_TIMEOUT
    } else {
        BACKGROUND_CONTINUE_PERMIT_TIMEOUT
    };
    let request_identity = format!(
        "{}:{}:{}",
        trigger,
        request.session_id.as_deref().unwrap_or("no_session"),
        material_watermark
    );
    let continue_permit = crate::workload::governor().acquire_request(
        crate::workload::WorkRequest::new(work_class)
            .identity(request_identity)
            .deadline(continue_permit_timeout),
    )?;
    if continue_permit.is_cancelled() {
        return Err("Continue request was superseded before computation".to_string());
    }
    let conn = open_db(&app)?;
    let effective_mode = crate::continuation::effective_continue_decision_mode(
        request.mode.as_deref(),
        request.rebuild_layers.unwrap_or(false),
    );
    match effective_mode {
        "rebuild" => {
            increment_maintenance_counter(&conn, "continue_rebuild_calls", 1)?;
        }
        _ => {
            increment_maintenance_counter(&conn, "continue_normal_calls", 1)?;
        }
    }
    let mut result = crate::continuation::get_continue_decision(&conn, request.clone())?;
    if continue_permit.is_cancelled() {
        return Err("background Continue result superseded by a newer manual request".to_string());
    }
    if let Some((probe_request, sufficiency)) =
        crate::continuation::build_need_more_evidence_request_from_decision(&conn, &result)?
    {
        let confidence_before = result.confidence_summary.clone();
        let mut probe_result = run_continue_evidence_probes(&app, &probe_request);
        let current_material_watermark =
            crate::continuation::current_continue_evidence_watermark_hash(
                &conn,
                request.session_id.as_deref(),
            )?;
        if current_material_watermark != probe_request.source_evidence_watermark_hash {
            probe_result.stale_result = true;
            probe_result.evidence_changed = false;
            probe_result.dimensions_changed.clear();
            for outcome in &mut probe_result.per_probe_outcomes {
                outcome.stale_result = true;
                outcome.dimensions_changed.clear();
            }
        }
        crate::continuation::record_continue_evidence_probe_result(
            &conn,
            &probe_request,
            &probe_result,
        )?;
        if continue_permit.is_cancelled() {
            return Err("background Continue probe superseded before rerun".to_string());
        }
        let reran_decision = crate::continuation::probe_result_allows_rerun(&probe_result);
        let rerun_reason = if probe_result.stale_result {
            "stale_result_isolated"
        } else if reran_decision {
            "material_requested_dimension_changed"
        } else {
            match probe_result.status {
                crate::continuation::EvidenceProbeStatus::SucceededNoChange => {
                    "succeeded_no_change"
                }
                crate::continuation::EvidenceProbeStatus::TimedOut => "timed_out",
                crate::continuation::EvidenceProbeStatus::PrivacyBlocked => "privacy_blocked",
                crate::continuation::EvidenceProbeStatus::PermissionBlocked => "permission_blocked",
                crate::continuation::EvidenceProbeStatus::Cancelled => "cancelled",
                crate::continuation::EvidenceProbeStatus::Failed => "failed",
                crate::continuation::EvidenceProbeStatus::NotApplicable => "not_applicable",
                crate::continuation::EvidenceProbeStatus::BudgetExhausted => "budget_exhausted",
                crate::continuation::EvidenceProbeStatus::SucceededChangedEvidence => {
                    "changed_without_material_requested_dimension"
                }
            }
        }
        .to_string();
        if reran_decision {
            result = crate::continuation::get_continue_decision(&conn, request.clone())?;
            result
                .warnings
                .push("observe_before_decide:evidence_refreshed_before_decision".to_string());
            result.warnings.sort();
            result.warnings.dedup();
        }
        let trace = crate::continuation::ObserveBeforeDecideTrace {
            schema: "smalltalk.observe_before_decide_trace.v2".to_string(),
            request: probe_request,
            sufficiency,
            reran_decision,
            rerun_reason,
            confidence_before,
            confidence_after: result.confidence_summary.clone(),
            stale_or_cancelled: probe_result.stale_result
                || matches!(
                    probe_result.status,
                    crate::continuation::EvidenceProbeStatus::Cancelled
                ),
            probe_result,
        };
        result.observe_before_decide = Some(trace);
    }
    if result.cache_hit {
        crate::workload::governor()
            .note_coalesced(work_class == crate::workload::WorkClass::BackgroundContinue);
        increment_maintenance_counter(&conn, "decision_cache_hits", 1)?;
    }
    if continue_output_audit_enabled(&request) {
        match schedule_continue_output_audit(&conn, &app, &request, effective_mode, &mut result) {
            Ok(summary) => {
                result.continue_output_path = Some(summary.path);
            }
            Err(error) => {
                let _ = increment_maintenance_counter(&conn, "continue_output_audit_failures", 1);
                result
                    .warnings
                    .push(format!("continue_output_audit_failed:{}", error));
            }
        }
    }
    if let Some(started_at_ms) = request.manual_continue_started_at_ms {
        let total_manual_continue_ms = now_millis().saturating_sub(started_at_ms);
        if let Err(error) = crate::continuation::task_truth_v2::finalize_manual_continue_performance(
            &conn,
            &result.decision_id,
            total_manual_continue_ms,
        ) {
            eprintln!("[mfti_04_performance] total finalization failed: {error}");
        }
    }
    if request.request_trigger.as_deref() == Some("manual")
        && matches!(
            crate::continuation::effective_continue_audit_mode(&request),
            crate::continuation::ContinueAuditMode::MftiReview
        )
    {
        if let Err(error) =
            crate::continuation::task_truth_v2::review::write_mfti_review_artifact(&conn, &result)
        {
            eprintln!("[mfti_review] artifact write failed: {error}");
        }
    }
    let history_created_at_ms = request
        .manual_continue_started_at_ms
        .unwrap_or_else(now_millis);
    if let Err(error) = crate::continuation::history::record_explicit_continue_output(
        &conn,
        &request,
        history_created_at_ms,
        &result,
    ) {
        // History is an optional read-only surface. A storage failure must not
        // turn an otherwise valid Continue answer into an application error.
        eprintln!("[continue_history] final output persistence failed: {error}");
    }
    Ok(result)
}

fn continue_output_audit_enabled(request: &crate::continuation::ContinueDecisionRequest) -> bool {
    request.request_trigger.as_deref() == Some("manual")
        && matches!(
            crate::continuation::effective_continue_audit_mode(request),
            crate::continuation::ContinueAuditMode::Full
        )
}

fn run_continue_evidence_probes(
    app: &AppHandle,
    request: &crate::continuation::NeedMoreEvidenceRequest,
) -> crate::continuation::NeedMoreEvidenceProbeResult {
    let started_at_ms = now_millis();
    let budget = Duration::from_millis(request.max_probe_ms.clamp(100, 5_000) as u64);
    let deadline = Instant::now() + budget;
    let mut warnings = Vec::new();
    let mut errors = Vec::new();
    let mut probes_succeeded = Vec::new();
    let mut context = AccessibilityContext::default();
    let mut window_count = 0_i64;
    let mut timed_out = false;
    let selected_probe = request.selected_probe.clone();
    let run_accessibility = matches!(
        selected_probe,
        crate::continuation::EvidenceProbeKind::FrontmostAppProbe
            | crate::continuation::EvidenceProbeKind::ActiveWindowProbe
            | crate::continuation::EvidenceProbeKind::BrowserUrlProbe
            | crate::continuation::EvidenceProbeKind::DocumentPathProbe
            | crate::continuation::EvidenceProbeKind::AccessibilityTextProbe
            | crate::continuation::EvidenceProbeKind::AppContextProbe
            | crate::continuation::EvidenceProbeKind::ActiveElementProbe
            | crate::continuation::EvidenceProbeKind::ScopedActiveWindowCapture
            | crate::continuation::EvidenceProbeKind::OcrIfAxThin
    );
    let run_window_graph = matches!(
        selected_probe,
        crate::continuation::EvidenceProbeKind::WindowGraphProbe
    );

    match capture_paths(app) {
        Ok(paths) => {
            if run_accessibility {
                let remaining = deadline
                    .checked_duration_since(Instant::now())
                    .unwrap_or_else(|| Duration::from_millis(0));
                let (next_context, accessibility_timed_out) =
                    collect_accessibility_context_with_timeout(paths.clone(), remaining);
                context = next_context;
                if accessibility_timed_out {
                    timed_out = true;
                    warnings.push("accessibility_probe_timed_out".to_string());
                }
                if context.error.is_some() {
                    warnings.push("accessibility_probe_returned_error".to_string());
                }
            }
            if run_window_graph {
                let remaining = deadline
                    .checked_duration_since(Instant::now())
                    .unwrap_or_else(|| Duration::from_millis(0));
                match collect_window_snapshot_with_timeout(paths, remaining) {
                    Ok((snapshot, false)) => {
                        window_count = snapshot.windows.len() as i64;
                        if context.app_bundle_id.is_none() {
                            context.app_bundle_id = snapshot.active_app_bundle_id.clone();
                        }
                        if context.window_id.is_none() {
                            context.window_id = snapshot.active_window_id;
                        }
                        if let Some(active) =
                            snapshot.windows.iter().find(|window| window.is_active)
                        {
                            if context.app_name.is_none() {
                                context.app_name = active.owner_name.clone();
                            }
                            if context.window_name.is_none() {
                                context.window_name = active.window_title.clone();
                            }
                        }
                    }
                    Ok((_, true)) => {
                        timed_out = true;
                        warnings.push("window_graph_probe_timed_out".to_string());
                    }
                    Err(error) if error == "window_graph_probe_timed_out" => {
                        timed_out = true;
                        warnings.push("window_graph_probe_timed_out".to_string())
                    }
                    Err(error) => errors.push(format!("window_graph_probe_failed:{}", error)),
                }
            }
        }
        Err(error) => errors.push(format!("capture_paths_failed:{}", error)),
    }

    let privacy = privacy_decision(app, &context).unwrap_or_else(|error| {
        warnings.push(format!("privacy_probe_failed:{}", error));
        PrivacyDecision {
            skip_capture: false,
            status: "unknown".to_string(),
            regions: Vec::new(),
        }
    });
    let privacy_blocked = privacy.skip_capture || privacy.status == "never_send_to_ai";
    if privacy_blocked {
        warnings.push("probe_privacy_blocked".to_string());
    }
    let redact_locators = privacy_blocked || privacy.status == "redacted";
    let completed_at_ms = now_millis();
    let observation_id = Some(format!(
        "continue-probe-{}",
        stable_hash_bytes(format!("{}:{}", request.id, completed_at_ms).as_bytes())
    ));
    let material_evidence_hash_after = stable_hash_bytes(
        serde_json::to_string(&serde_json::json!({
            "app_name": context.app_name.as_deref(),
            "app_bundle_id": context.app_bundle_id.as_deref(),
            "window_title": context.window_name.as_deref(),
            "browser_url": context.browser_url.as_deref(),
            "document_path": context.document_path.as_deref(),
        }))
        .unwrap_or_default()
        .as_bytes(),
    );
    let can_materially_change = request.requested_dimensions.iter().any(|dimension| {
        matches!(
            dimension,
            crate::continuation::ConfidenceDimension::SurfaceIdentity
                | crate::continuation::ConfidenceDimension::ActiveWindowOwnership
                | crate::continuation::ConfidenceDimension::TargetIdentity
                | crate::continuation::ConfidenceDimension::TargetOpenability
                | crate::continuation::ConfidenceDimension::DirectTargetPolicy
        )
    });
    let evidence_changed = !privacy_blocked
        && !timed_out
        && errors.is_empty()
        && can_materially_change
        && material_evidence_hash_after != request.source_surface_fingerprint;
    let status = if privacy_blocked {
        crate::continuation::EvidenceProbeStatus::PrivacyBlocked
    } else if timed_out || completed_at_ms > request.deadline_at_ms {
        crate::continuation::EvidenceProbeStatus::TimedOut
    } else if !errors.is_empty() || context.error.is_some() {
        crate::continuation::EvidenceProbeStatus::Failed
    } else if evidence_changed {
        crate::continuation::EvidenceProbeStatus::SucceededChangedEvidence
    } else {
        crate::continuation::EvidenceProbeStatus::SucceededNoChange
    };
    if matches!(
        status,
        crate::continuation::EvidenceProbeStatus::SucceededChangedEvidence
            | crate::continuation::EvidenceProbeStatus::SucceededNoChange
    ) {
        probes_succeeded.push(selected_probe.clone());
    }
    let dimensions_changed = if evidence_changed {
        request
            .requested_dimensions
            .iter()
            .filter(|dimension| {
                matches!(
                    dimension,
                    crate::continuation::ConfidenceDimension::SurfaceIdentity
                        | crate::continuation::ConfidenceDimension::ActiveWindowOwnership
                        | crate::continuation::ConfidenceDimension::TargetIdentity
                        | crate::continuation::ConfidenceDimension::TargetOpenability
                        | crate::continuation::ConfidenceDimension::DirectTargetPolicy
                )
            })
            .copied()
            .collect::<Vec<_>>()
    } else {
        Vec::new()
    };
    let evidence_record_ids = evidence_changed
        .then(|| observation_id.clone())
        .flatten()
        .into_iter()
        .collect::<Vec<_>>();
    let per_probe_outcomes = request
        .requested_dimensions
        .iter()
        .map(|dimension| crate::continuation::EvidenceProbeOutcome {
            probe_kind: selected_probe.clone(),
            requested_dimension: *dimension,
            started_at_ms,
            completed_at_ms,
            deadline_at_ms: request.deadline_at_ms,
            status: status.clone(),
            success_criteria: request.success_criteria.clone(),
            evidence_record_ids: evidence_record_ids.clone(),
            dimensions_changed: dimensions_changed.clone(),
            failure_reason: (!matches!(
                status,
                crate::continuation::EvidenceProbeStatus::SucceededChangedEvidence
                    | crate::continuation::EvidenceProbeStatus::SucceededNoChange
            ))
            .then(|| {
                warnings
                    .first()
                    .cloned()
                    .or_else(|| errors.first().cloned())
                    .unwrap_or_else(|| status.as_str().to_string())
            }),
            stale_result: false,
        })
        .collect::<Vec<_>>();

    crate::continuation::NeedMoreEvidenceProbeResult {
        request_id: request.id.clone(),
        started_at_ms,
        completed_at_ms,
        probes_attempted: vec![selected_probe],
        probes_succeeded,
        evidence_changed,
        privacy_blocked,
        observation_id,
        app_name: (!privacy_blocked)
            .then(|| context.app_name.clone())
            .flatten(),
        app_bundle_id: (!privacy_blocked)
            .then(|| context.app_bundle_id.clone())
            .flatten(),
        window_title: (!privacy_blocked)
            .then(|| context.window_name.clone())
            .flatten(),
        browser_url: (!redact_locators)
            .then(|| context.browser_url.clone())
            .flatten(),
        document_path: (!redact_locators)
            .then(|| context.document_path.clone())
            .flatten(),
        accessibility_text_char_count: if privacy_blocked {
            0
        } else {
            context.text.chars().count() as i64
        },
        window_count: if privacy_blocked { 0 } else { window_count },
        privacy_status: Some(privacy.status),
        warnings,
        errors,
        deadline_at_ms: request.deadline_at_ms,
        status,
        per_probe_outcomes,
        evidence_record_ids,
        dimensions_changed,
        stale_result: false,
        material_evidence_hash_before: request.source_surface_fingerprint.clone(),
        material_evidence_hash_after,
    }
}

fn collect_accessibility_context_with_timeout(
    paths: CapturePaths,
    timeout: Duration,
) -> (AccessibilityContext, bool) {
    if timeout.is_zero() {
        return (
            AccessibilityContext {
                error: Some("accessibility_probe_timed_out".to_string()),
                ..AccessibilityContext::default()
            },
            true,
        );
    }
    // The old wrapper abandoned a detached thread after recv_timeout. The
    // bounded runner now owns the real child deadline, kill, and reap path.
    let native_deadline = timeout.min(ACCESSIBILITY_DEADLINE) / 2;
    let fallback_deadline = timeout
        .saturating_sub(native_deadline)
        .min(ACCESSIBILITY_APPLESCRIPT_DEADLINE);
    let context = collect_accessibility_context_bounded(
        &paths,
        native_deadline.max(Duration::from_millis(1)),
        fallback_deadline.max(Duration::from_millis(1)),
        None,
    );
    let timed_out = context
        .error
        .as_deref()
        .is_some_and(|error| error.contains("timeout") || error.contains("timed out"));
    (context, timed_out)
}

fn collect_window_snapshot_with_timeout(
    paths: CapturePaths,
    timeout: Duration,
) -> Result<(WindowSnapshotPayload, bool), String> {
    if timeout.is_zero() {
        return Err("window_graph_probe_timed_out".to_string());
    }
    collect_window_snapshot(&paths, timeout.min(WINDOW_SNAPSHOT_DEADLINE), None)
        .map(|snapshot| (snapshot, false))
}

