fn audit_executor() -> &'static AuditExecutor {
    AUDIT_EXECUTOR.get_or_init(|| {
        let state = Arc::new((Mutex::new(AuditExecutorState::default()), Condvar::new()));
        let worker_state = state.clone();
        let worker = thread::Builder::new()
            .name("smalltalk-audit-executor".to_string())
            .spawn(move || audit_executor_loop(worker_state))
            .ok();
        AuditExecutor {
            state,
            worker: Mutex::new(worker),
        }
    })
}

impl AuditExecutor {
    fn schedule(&self, job: ContinueAuditJob) -> bool {
        if self
            .worker
            .lock()
            .unwrap_or_else(|poisoned| poisoned.into_inner())
            .is_none()
        {
            return false;
        }
        let (lock, changed) = &*self.state;
        let mut state = lock.lock().unwrap_or_else(|poisoned| poisoned.into_inner());
        if state.shutting_down {
            return false;
        }
        if state.active_identity.as_deref() == Some(job.identity.as_str())
            || state
                .pending
                .as_ref()
                .is_some_and(|pending| pending.identity == job.identity)
        {
            state.coalesced = state.coalesced.saturating_add(1);
            return true;
        }
        if let Some(previous) = state.pending.replace(job) {
            previous.cancellation.cancel();
            state.superseded = state.superseded.saturating_add(1);
        }
        state.submitted = state.submitted.saturating_add(1);
        changed.notify_one();
        true
    }

    fn diagnostics(&self) -> AuditExecutorDiagnostics {
        let state = self
            .state
            .0
            .lock()
            .unwrap_or_else(|poisoned| poisoned.into_inner());
        AuditExecutorDiagnostics {
            active: state.active_identity.is_some(),
            queued: u64::from(state.pending.is_some()),
            queue_capacity: 1,
            submitted: state.submitted,
            completed: state.completed,
            failed: state.failed,
            coalesced: state.coalesced,
            superseded: state.superseded,
            shutting_down: state.shutting_down,
        }
    }

    fn shutdown(&self) {
        let (lock, changed) = &*self.state;
        let mut state = lock.lock().unwrap_or_else(|poisoned| poisoned.into_inner());
        state.shutting_down = true;
        if let Some(cancellation) = state.active_cancellation.as_ref() {
            cancellation.cancel();
        }
        if let Some(pending) = state.pending.take() {
            pending.cancellation.cancel();
            state.superseded = state.superseded.saturating_add(1);
        }
        changed.notify_all();
    }
}

fn audit_executor_loop(shared: Arc<(Mutex<AuditExecutorState>, Condvar)>) {
    loop {
        let job = {
            let (lock, changed) = &*shared;
            let mut state = lock.lock().unwrap_or_else(|poisoned| poisoned.into_inner());
            while state.pending.is_none() && !state.shutting_down {
                state = changed
                    .wait(state)
                    .unwrap_or_else(|poisoned| poisoned.into_inner());
            }
            if state.shutting_down && state.pending.is_none() {
                return;
            }
            let job = state.pending.take();
            if let Some(job) = job.as_ref() {
                state.active_identity = Some(job.identity.clone());
                state.active_cancellation = Some(job.cancellation.clone());
            }
            job
        };
        let Some(mut job) = job else {
            continue;
        };
        let work_request =
            crate::workload::WorkRequest::new(crate::workload::WorkClass::AuditExport)
                .identity(job.identity.clone())
                .deadline(Duration::from_secs(2))
                .cancellation(job.cancellation.clone());
        let export_result = match crate::workload::governor().acquire_request(work_request) {
            Ok(mut permit) if !permit.is_cancelled() => {
                let result = (|| -> Result<(), String> {
                    let conn = open_db_at_path(&job.db_path, true)?;
                    export_continue_output_audit_to_plan(
                        &conn,
                        &job.request,
                        &job.effective_mode,
                        &mut job.result,
                        &job.plan,
                    )
                    .map(|_| ())
                })();
                if result.is_err() {
                    permit.mark_failed();
                }
                result
            }
            Ok(_) => Err("audit export cancelled before execution".to_string()),
            Err(error) => Err(error),
        };
        if let Err(error) = export_result.as_ref() {
            eprintln!("[continue_output_audit] failed: {error}");
            if let Ok(conn) = open_db_at_path(&job.db_path, true) {
                let _ = increment_maintenance_counter(&conn, "continue_output_audit_failures", 1);
            }
        }
        let (lock, changed) = &*shared;
        let mut state = lock.lock().unwrap_or_else(|poisoned| poisoned.into_inner());
        state.active_identity = None;
        state.active_cancellation = None;
        if export_result.is_ok() {
            state.completed = state.completed.saturating_add(1);
        } else {
            state.failed = state.failed.saturating_add(1);
        }
        changed.notify_all();
    }
}

pub(crate) fn shutdown_audit_executor() {
    if let Some(executor) = AUDIT_EXECUTOR.get() {
        executor.shutdown();
    }
}

fn audit_executor_diagnostics() -> AuditExecutorDiagnostics {
    AUDIT_EXECUTOR
        .get()
        .map(AuditExecutor::diagnostics)
        .unwrap_or_default()
}

fn schedule_continue_output_audit(
    conn: &Connection,
    app: &AppHandle,
    request: &crate::continuation::ContinueDecisionRequest,
    effective_mode: &str,
    result: &mut crate::continuation::ContinueDecisionResult,
) -> Result<ContinueOutputExportSummary, String> {
    let output_root = project_continue_outputs_root()?;
    let plan = continue_output_audit_plan(conn, &output_root, request, effective_mode, result);
    result.continue_output_path = Some(plan.final_dir.to_string_lossy().to_string());
    let summary = ContinueOutputExportSummary {
        schema: "smalltalk.continue_output.full_audit.v1".to_string(),
        generated_at_ms: plan.generated_at_ms,
        decision_id: result.decision_id.clone(),
        folder_name: plan.folder_name.clone(),
        path: plan.final_dir.to_string_lossy().to_string(),
        file_count: 0,
        byte_size: 0,
        warning_count: 0,
    };

    let db_path = capture_paths(app)?.db_path;
    let mut audit_result = result.clone();
    audit_result.continue_output_path = Some(summary.path.clone());
    let scheduled = audit_executor().schedule(ContinueAuditJob {
        identity: result.decision_id.clone(),
        db_path,
        request: request.clone(),
        effective_mode: effective_mode.to_string(),
        result: audit_result,
        plan,
        cancellation: crate::workload::WorkCancellationToken::default(),
    });
    if !scheduled {
        return Err("bounded audit executor is unavailable or shutting down".to_string());
    }

    Ok(summary)
}

fn continue_output_audit_plan(
    conn: &Connection,
    output_root: &Path,
    request: &crate::continuation::ContinueDecisionRequest,
    effective_mode: &str,
    result: &crate::continuation::ContinueDecisionResult,
) -> ContinueOutputAuditPlan {
    let generated_at_ms = now_millis();
    let session_label = continue_output_session_label(conn, request, result)
        .unwrap_or_else(|| "session-unknown".to_string());
    let decision_label = short_sanitized_id(&result.decision_id, 18);
    let mode_label = sanitize_id(effective_mode);
    let folder_name = format!(
        "{}__continue-{}__{}__{}",
        session_label, generated_at_ms, mode_label, decision_label
    );
    ContinueOutputAuditPlan {
        generated_at_ms,
        session_label,
        folder_name: folder_name.clone(),
        final_dir: output_root.join(&folder_name),
    }
}

fn continue_output_session_label(
    conn: &Connection,
    request: &crate::continuation::ContinueDecisionRequest,
    result: &crate::continuation::ContinueDecisionResult,
) -> Option<String> {
    let session_id = request
        .session_id
        .clone()
        .or_else(|| {
            result
                .current_focus
                .as_ref()
                .and_then(|focus| focus.frame_id.parse::<i64>().ok())
                .and_then(|frame_id| frame_session_id(conn, frame_id).ok().flatten())
        })
        .or_else(|| {
            result
                .resume_work_target
                .as_ref()
                .or(result.return_target.as_ref())
                .and_then(|target| target.fallback_frame_id.as_ref())
                .and_then(|frame_id| frame_id.parse::<i64>().ok())
                .and_then(|frame_id| frame_session_id(conn, frame_id).ok().flatten())
        })
        .or_else(|| latest_session_id(conn).ok().flatten())?;

    let session_stem = load_capture_session(conn, &session_id)
        .map(|session| session_folder_name(session.sequence))
        .unwrap_or_else(|_| "session".to_string());
    let session_id_stem = short_sanitized_id(&session_id, 16);
    if session_id_stem.is_empty() {
        Some(session_stem)
    } else {
        Some(format!("{}-{}", session_stem, session_id_stem))
    }
}

fn short_sanitized_id(value: &str, max_chars: usize) -> String {
    let sanitized = sanitize_id(value);
    if sanitized.chars().count() <= max_chars {
        sanitized
    } else {
        sanitized.chars().take(max_chars).collect()
    }
}

