fn export_continue_output_audit_to_plan(
    conn: &Connection,
    request: &crate::continuation::ContinueDecisionRequest,
    effective_mode: &str,
    result: &mut crate::continuation::ContinueDecisionResult,
    plan: &ContinueOutputAuditPlan,
) -> Result<ContinueOutputExportSummary, String> {
    crate::continuation::ensure_continue_schema(conn)?;
    let generated_at = plan.generated_at_ms;
    let folder_name = plan.folder_name.clone();
    let final_dir = plan.final_dir.clone();
    if let Some(output_root) = final_dir.parent() {
        fs::create_dir_all(output_root).map_err(to_string)?;
    }
    let tmp_dir = final_dir
        .parent()
        .map(|parent| parent.join(format!(".{}.building", plan.folder_name)))
        .unwrap_or_else(|| final_dir.with_extension("building"));
    if tmp_dir.exists() {
        fs::remove_dir_all(&tmp_dir).map_err(|error| {
            format!(
                "remove stale audit tmp dir {}: {}",
                tmp_dir.display(),
                error
            )
        })?;
    }
    if final_dir.exists() {
        fs::remove_dir_all(&final_dir).map_err(|error| {
            format!(
                "remove stale audit final dir {}: {}",
                final_dir.display(),
                error
            )
        })?;
    }
    fs::create_dir_all(&tmp_dir).map_err(to_string)?;
    result.continue_output_path = Some(final_dir.to_string_lossy().to_string());

    let mut warnings = Vec::new();
    let mut raw_errors = Vec::new();
    let mut skipped_tables = Vec::new();
    let mut raw_table_manifest = Vec::new();
    let mut frame_manifests = Vec::new();
    let mut layer_manifest = Vec::new();
    let mut candidate_manifest = Vec::new();

    let output_dir = tmp_dir;
    let raw_dir = output_dir.join("raw");
    let raw_tables_dir = raw_dir.join("tables");
    let request_dir = output_dir.join("request");
    let capture_frames_dir = output_dir.join("capture").join("frames");
    let layers_dir = output_dir.join("continue").join("layers");
    let candidates_dir = output_dir.join("continue").join("candidates");
    let semantic_dir = output_dir.join("semantic");
    let inference_dir = output_dir.join("inference");
    let final_output_dir = output_dir.join("final");
    let decision_dir = output_dir.join("decision");
    let evidence_dir = output_dir.join("evidence");
    let evidence_frames_dir = evidence_dir.join("frames");
    let cache_dir = output_dir.join("cache");
    let model_dir = output_dir.join("model");
    let activity_recap_dir = output_dir.join("activity_recap");
    let logs_dir = output_dir.join("logs");
    for dir in [
        &raw_dir,
        &request_dir,
        &layers_dir,
        &candidates_dir,
        &semantic_dir,
        &inference_dir,
        &final_output_dir,
        &decision_dir,
        &evidence_dir,
        &evidence_frames_dir,
        &cache_dir,
        &model_dir,
        &activity_recap_dir,
        &logs_dir,
    ] {
        fs::create_dir_all(dir).map_err(to_string)?;
    }
    write_json_pretty(
        &output_dir.join("BUILDING_AUDIT.json"),
        &serde_json::json!({
            "schema": "smalltalk.continue_audit_building.v1",
            "folderName": folder_name,
            "decisionId": result.decision_id,
            "startedAtMs": now_millis(),
            "finalPath": final_dir.to_string_lossy(),
        }),
    )?;

    write_continue_export_status(
        &output_dir,
        "running",
        "critical_started",
        result,
        &warnings,
        &raw_errors,
        &skipped_tables,
    )?;
    write_continue_disk_status(&output_dir.join("disk_status.json"), &output_dir)?;

    write_json_pretty(
        &request_dir.join("get_continue_decision_request.json"),
        &serde_json::json!({
            "schema": "smalltalk.continue_output.request.v1",
            "effectiveMode": effective_mode,
            "request": request,
            "normalizedDefaults": {
                "lookback_ms": request.lookback_ms.unwrap_or(45 * 60 * 1000),
                "limit": request.limit.unwrap_or(700),
                "mode": request.mode.as_deref().unwrap_or("normal"),
                "rebuild_layers": request.rebuild_layers.unwrap_or(false),
                "micro_inference_enabled": request.micro_inference_enabled.unwrap_or(true),
                "activity_recap_model_enabled": request.activity_recap_model_enabled.unwrap_or(false),
                "max_candidates_for_model": request.max_candidates_for_model.unwrap_or(5),
            }
        }),
    )?;

    let model_input_preview = conn
        .query_row(
            "SELECT a.packet_summary_json, a.keyframe_reasons_json,
                    a.canonical_conflicts_json, a.causal_edges_json,
                    p.packet_json
             FROM task_truth_v2_shadow_audits a
             JOIN task_truth_v2_observation_packets p ON p.packet_id = a.packet_id
             WHERE a.decision_id = ?1
             ORDER BY a.observed_at_ms DESC LIMIT 1",
            params![result.decision_id],
            |row| {
                let packet_summary: String = row.get(0)?;
                let keyframes: String = row.get(1)?;
                let conflicts: String = row.get(2)?;
                let interactions: String = row.get(3)?;
                let packet: String = row.get(4)?;
                Ok(serde_json::json!({
                    "schema": "smalltalk.model_input_preview.v1",
                    "private_developer_audit_only": true,
                    "effective_session_id": request.session_id,
                    "packet_summary": serde_json::from_str::<Value>(&packet_summary).unwrap_or(Value::Null),
                    "selected_keyframes_chronological": serde_json::from_str::<Value>(&keyframes).unwrap_or(Value::Null),
                    "ownership_conflicts": serde_json::from_str::<Value>(&conflicts).unwrap_or(Value::Null),
                    "causal_interactions": serde_json::from_str::<Value>(&interactions).unwrap_or(Value::Null),
                    "packet": serde_json::from_str::<Value>(&packet).unwrap_or(Value::Null),
                }))
            },
        )
        .optional()
        .map_err(to_string)?
        .unwrap_or_else(|| serde_json::json!({
            "schema": "smalltalk.model_input_preview.v1",
            "private_developer_audit_only": true,
            "effective_session_id": request.session_id,
            "status": "shadow_packet_unavailable"
        }));
    write_json_pretty(
        &model_dir.join("model_input_preview.json"),
        &model_input_preview,
    )?;

    let inference_manifest =
        export_continue_inference_events(&inference_dir, &result.audit_inference_events)?;
    write_json_pretty(
        &candidates_dir.join("selected_candidate.json"),
        &selected_continue_candidate_json(conn, &result.decision_id)?,
    )?;
    write_json_pretty(
        &candidates_dir.join("alternatives.json"),
        &serde_json::to_value(&result.alternatives).map_err(to_string)?,
    )?;
    write_json_pretty(
        &candidates_dir.join("missing_evidence.json"),
        &serde_json::to_value(&result.missing_evidence).map_err(to_string)?,
    )?;
    write_json_pretty(
        &candidates_dir.join("warnings.json"),
        &serde_json::to_value(&result.warnings).map_err(to_string)?,
    )?;
    write_json_pretty(
        &final_output_dir.join("continue_decision_result.json"),
        &serde_json::to_value(&result).map_err(to_string)?,
    )?;
    write_json_pretty(
        &final_output_dir.join("handoff.json"),
        &serde_json::to_value(&result.handoff).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("confidence_vector.json"),
        &serde_json::to_value(&result.confidence_vector).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("confidence_compatibility.json"),
        &serde_json::json!({
            "summary": result.confidence_summary,
            "legacyDerivation": result.legacy_confidence_derivation,
            "claimDependencies": crate::continuation::ConfidenceClaim::ALL
                .into_iter()
                .map(|claim| (
                    claim.as_str(),
                    crate::continuation::confidence::claim_dependencies(claim),
                ))
                .collect::<std::collections::BTreeMap<_, _>>(),
        }),
    )?;
    write_text_file(
        &semantic_dir.join("app_activity_segments.ndjson"),
        &continue_app_activity_segments_ndjson(result)?,
    )?;
    write_text_file(
        &semantic_dir.join("activity_classifications.ndjson"),
        &continue_activity_classifications_ndjson(result)?,
    )?;
    write_text_file(
        &semantic_dir.join("work_value_summary.md"),
        &continue_work_value_summary_markdown(result),
    )?;
    write_json_pretty(
        &output_dir.join("memory_retrieval.json"),
        &serde_json::to_value(&result.memory_retrieval).map_err(to_string)?,
    )?;
    write_json_pretty(
        &output_dir.join("continue_dossier.json"),
        &serde_json::to_value(&result.continue_dossier).map_err(to_string)?,
    )?;
    write_text_file(
        &output_dir.join("memory_retrieval_explain.md"),
        &continue_memory_retrieval_explain_markdown(result),
    )?;
    if let Some(trace) = result.observe_before_decide.as_ref() {
        write_json_pretty(
            &output_dir.join("need_more_evidence_request.json"),
            &serde_json::to_value(&trace.request).map_err(to_string)?,
        )?;
        write_json_pretty(
            &output_dir.join("need_more_evidence_probe_result.json"),
            &serde_json::to_value(&trace.probe_result).map_err(to_string)?,
        )?;
        write_text_file(
            &output_dir.join("observe_before_decide_trace.md"),
            &observe_before_decide_trace_markdown(trace),
        )?;
    }

    write_continue_export_status(
        &output_dir,
        "running",
        "critical_complete_raw_pending",
        result,
        &warnings,
        &raw_errors,
        &skipped_tables,
    )?;

    let selected_candidate = selected_continue_candidate_json(conn, &result.decision_id)?;
    match export_continue_table_group(conn, &layers_dir, CONTINUE_OUTPUT_LAYER_TABLES) {
        Ok(manifest) => layer_manifest = manifest,
        Err(error) => push_continue_raw_error(
            &mut raw_errors,
            &mut warnings,
            "continue_layers",
            "continue_layer_export_failed",
            error,
            None,
        ),
    }
    match export_continue_table_group(conn, &candidates_dir, CONTINUE_OUTPUT_CANDIDATE_TABLES) {
        Ok(manifest) => candidate_manifest = manifest,
        Err(error) => push_continue_raw_error(
            &mut raw_errors,
            &mut warnings,
            "continue_candidates",
            "continue_candidate_export_failed",
            error,
            None,
        ),
    }

    #[cfg(test)]
    let force_raw_failure = effective_mode == "force_raw_failure_for_test";
    #[cfg(not(test))]
    let force_raw_failure = false;
    let full_raw_export = continue_audit_full_raw_enabled(effective_mode);

    if force_raw_failure {
        push_continue_raw_error(
            &mut raw_errors,
            &mut warnings,
            "raw_tables",
            "forced_raw_table_failure",
            "forced raw table failure for regression coverage".to_string(),
            None,
        );
        skipped_tables.push(serde_json::json!({
            "table": "*",
            "reason": "forced_raw_table_failure"
        }));
        write_sqlite_snapshot_skipped_metadata(
            &raw_dir,
            "raw/smalltalk-capture.sqlite",
            "forced_raw_table_failure",
        )?;
    } else if full_raw_export {
        fs::create_dir_all(&raw_tables_dir).map_err(to_string)?;
        fs::create_dir_all(&capture_frames_dir).map_err(to_string)?;
        match copy_database_snapshot(conn, &raw_dir.join("smalltalk-capture.sqlite")) {
            Ok(()) => {
                write_sqlite_snapshot_metadata(
                    &raw_dir,
                    "raw/smalltalk-capture.sqlite",
                    &raw_dir.join("smalltalk-capture.sqlite"),
                    None,
                )?;
            }
            Err(error) => {
                push_continue_raw_error(
                    &mut raw_errors,
                    &mut warnings,
                    "raw_database",
                    "database_snapshot_failed",
                    error.clone(),
                    Some("raw/smalltalk-capture.sqlite".to_string()),
                );
                let _ = write_sqlite_snapshot_metadata(
                    &raw_dir,
                    "raw/smalltalk-capture.sqlite",
                    &raw_dir.join("smalltalk-capture.sqlite"),
                    Some(error),
                );
            }
        }
        match write_schema_dump(conn, &raw_dir.join("schema.sql")) {
            Ok(()) => {}
            Err(error) => push_continue_raw_error(
                &mut raw_errors,
                &mut warnings,
                "raw_schema",
                "schema_dump_failed",
                error,
                Some("raw/schema.sql".to_string()),
            ),
        }
        match export_all_tables_streaming_ndjson(conn, &raw_tables_dir, &mut warnings) {
            Ok((manifest, skipped)) => {
                raw_table_manifest = manifest;
                skipped_tables.extend(skipped);
            }
            Err(error) => push_continue_raw_error(
                &mut raw_errors,
                &mut warnings,
                "raw_tables",
                "raw_table_manifest_failed",
                error,
                Some("raw/tables".to_string()),
            ),
        }
        match all_frames_for_continue_output(conn) {
            Ok(frames) => {
                for (index, frame) in frames.iter().enumerate() {
                    match export_frame_folder(
                        conn,
                        frame,
                        index + 1,
                        &capture_frames_dir,
                        &mut warnings,
                    ) {
                        Ok(manifest) => frame_manifests.push(manifest),
                        Err(error) => push_continue_raw_error(
                            &mut raw_errors,
                            &mut warnings,
                            "capture_frames",
                            "frame_export_failed",
                            error,
                            Some(format!("capture/frames/frame-{:06}", index + 1)),
                        ),
                    }
                }
            }
            Err(error) => push_continue_raw_error(
                &mut raw_errors,
                &mut warnings,
                "capture_frames",
                "frame_manifest_query_failed",
                error,
                Some("capture/frames".to_string()),
            ),
        }
    } else {
        write_sqlite_snapshot_skipped_metadata(
            &raw_dir,
            "raw/smalltalk-capture.sqlite",
            "default_lean_continue_audit",
        )?;
        skipped_tables.push(serde_json::json!({
            "scope": "raw_database",
            "reason": "default_lean_continue_audit",
            "message": "Full SQLite snapshots are disabled for default Continue audits. Use SMALLTALK_CONTINUE_AUDIT_FULL_RAW=1 or an effective mode containing full_raw for archival debug output."
        }));
        skipped_tables.push(serde_json::json!({
            "scope": "raw_tables",
            "reason": "default_lean_continue_audit",
            "message": "Full raw table NDJSON export is disabled for default Continue audits."
        }));
        skipped_tables.push(serde_json::json!({
            "scope": "capture_frames",
            "reason": "default_lean_continue_audit",
            "message": "All-frame capture export is disabled for default Continue audits; selected evidence frames are exported under evidence/frames."
        }));
        match write_schema_dump(conn, &raw_dir.join("schema.sql")) {
            Ok(()) => {}
            Err(error) => push_continue_raw_error(
                &mut raw_errors,
                &mut warnings,
                "raw_schema",
                "schema_dump_failed",
                error,
                Some("raw/schema.sql".to_string()),
            ),
        }
    }

    write_json_pretty(
        &decision_dir.join("final_decision.json"),
        &serde_json::to_value(&result).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("work-truth.json"),
        &serde_json::to_value(&result.work_truth).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("current_focus.json"),
        &serde_json::to_value(&result.current_focus).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("active_current_work_unresolved.json"),
        &active_current_work_unresolved_audit_json(&result.active_current_work_unresolved),
    )?;
    write_json_pretty(
        &decision_dir.join("p0_quality_signals.json"),
        &serde_json::to_value(&result.p0_quality_signals).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("current_surface_resolution.json"),
        &serde_json::to_value(&result.current_surface_resolution).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("evidence_freshness_ledger.json"),
        &serde_json::to_value(&result.evidence_freshness_ledger).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("surface-enrichment-attempts.json"),
        &continue_surface_enrichment_attempts_audit_json(conn, result)?,
    )?;
    write_json_pretty(
        &decision_dir.join("surface-snapshots.json"),
        &continue_surface_snapshots_audit_json(conn, result)?,
    )?;
    write_json_pretty(
        &decision_dir.join("task-turn-evidence.json"),
        &crate::continuation::task_turn_evidence::task_turn_evidence_audit_json(conn, 240)?,
    )?;
    write_json_pretty(
        &decision_dir.join("current-task-turn.json"),
        &crate::continuation::task_turn::task_turn_audit_json(conn, 40)?,
    )?;
    write_json_pretty(
        &decision_dir.join("enriched-current-focus.json"),
        &continue_enriched_current_focus_audit_json(conn, result)?,
    )?;
    write_json_pretty(
        &decision_dir.join("weak-surface-candidate-gates.json"),
        &continue_weak_surface_candidate_gates_audit_json(result),
    )?;
    write_json_pretty(
        &decision_dir.join("selected_workstream.json"),
        &serde_json::to_value(&result.selected_workstream).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("return_target.json"),
        &serde_json::to_value(&result.return_target).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("resume_work_target.json"),
        &serde_json::to_value(&result.resume_work_target).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("evidence_anchors.json"),
        &serde_json::to_value(&result.evidence_anchors).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("alternatives.json"),
        &serde_json::to_value(&result.alternatives).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("warnings.json"),
        &serde_json::to_value(&result.warnings).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("missing_evidence.json"),
        &serde_json::to_value(&result.missing_evidence).map_err(to_string)?,
    )?;
    write_json_pretty(
        &decision_dir.join("candidates.json"),
        &continue_candidates_audit_json(result, &selected_candidate),
    )?;
    let copy_gate = continue_copy_gate_json(result);
    write_json_pretty(&decision_dir.join("copy_gate.json"), &copy_gate)?;
    let cache_decision = continue_cache_decision_json(result);
    write_json_pretty(&cache_dir.join("cache_decision.json"), &cache_decision)?;
    let model_summary = export_continue_model_audit(&model_dir, result, &inference_manifest)?;
    export_activity_recap_model_audit(&activity_recap_dir, result)?;
    let mut evidence_closure = continue_evidence_closure_from_result(result, &selected_candidate);
    export_selected_evidence_frames(
        conn,
        &evidence_frames_dir,
        &mut evidence_closure,
        &mut warnings,
    )?;
    let evidence_closure_json = evidence_closure_json(&evidence_closure);
    write_json_pretty(
        &evidence_dir.join("evidence_closure.json"),
        &evidence_closure_json,
    )?;
    write_continue_raw_table_index(&raw_dir, &raw_table_manifest, &skipped_tables)?;
    let decision_trace = continue_decision_trace_json(
        generated_at,
        effective_mode,
        request,
        result,
        &cache_decision,
        &model_summary,
        &copy_gate,
        &evidence_closure_json,
    );
    write_json_pretty(&decision_dir.join("decision_trace.json"), &decision_trace)?;

    write_json_pretty(
        &raw_dir.join("export_errors.json"),
        &Value::Array(raw_errors.clone()),
    )?;
    write_json_pretty(
        &raw_dir.join("skipped_tables.json"),
        &Value::Array(skipped_tables.clone()),
    )?;
    write_json_pretty(
        &output_dir.join("export_warnings.json"),
        &Value::Array(
            warnings
                .iter()
                .map(serde_json::to_value)
                .collect::<Result<Vec<_>, _>>()
                .map_err(to_string)?,
        ),
    )?;
    write_continue_export_status(
        &output_dir,
        if raw_errors.is_empty() {
            "complete"
        } else {
            "complete_with_raw_errors"
        },
        "finished",
        result,
        &warnings,
        &raw_errors,
        &skipped_tables,
    )?;
    write_continue_disk_status(&output_dir.join("disk_status.json"), &output_dir)?;
    write_text_file(
        &output_dir.join("explain.md"),
        &continue_output_explain_markdown_v2(
            result,
            frame_manifests.len(),
            &inference_manifest,
            &model_summary,
            &cache_decision,
            &copy_gate,
            &evidence_closure_json,
            if raw_errors.is_empty() {
                "complete"
            } else {
                "complete_with_warnings"
            },
        ),
    )?;
    let integrity = continue_audit_integrity_json(
        &output_dir,
        result,
        &raw_table_manifest,
        &evidence_closure_json,
        &cache_decision,
        &model_summary,
        &copy_gate,
        &raw_errors,
    );
    write_json_pretty(&output_dir.join("audit_integrity.json"), &integrity)?;
    write_continue_output_manifest(
        &output_dir,
        generated_at,
        &folder_name,
        plan,
        effective_mode,
        result,
        &raw_table_manifest,
        &frame_manifests,
        &layer_manifest,
        &candidate_manifest,
        &inference_manifest,
        &warnings,
        &raw_errors,
        &skipped_tables,
    )?;
    let _ = fs::remove_file(output_dir.join("BUILDING_AUDIT.json"));
    if let Some(parent) = final_dir.parent() {
        fs::create_dir_all(parent).map_err(to_string)?;
    }
    if final_dir.exists() {
        fs::remove_dir_all(&final_dir).map_err(|error| {
            format!(
                "remove pre-publish audit final dir {}: {}",
                final_dir.display(),
                error
            )
        })?;
    }
    fs::rename(&output_dir, &final_dir).map_err(|error| {
        format!(
            "publish audit dir {} -> {}: {}",
            output_dir.display(),
            final_dir.display(),
            error
        )
    })?;
    let stats = directory_stats(&final_dir).unwrap_or(ExportStats {
        file_count: 0,
        byte_size: 0,
    });

    Ok(ContinueOutputExportSummary {
        schema: "smalltalk.continue_output.full_audit.v1".to_string(),
        generated_at_ms: generated_at,
        decision_id: result.decision_id.clone(),
        folder_name,
        path: final_dir.to_string_lossy().to_string(),
        file_count: stats.file_count,
        byte_size: stats.byte_size,
        warning_count: warnings.len() as i64,
    })
}

fn write_continue_export_status(
    output_dir: &Path,
    status: &str,
    stage: &str,
    result: &crate::continuation::ContinueDecisionResult,
    warnings: &[ExportWarning],
    raw_errors: &[Value],
    skipped_tables: &[Value],
) -> Result<(), String> {
    let stats = directory_stats(output_dir).unwrap_or(ExportStats {
        file_count: 0,
        byte_size: 0,
    });
    let lean_raw_skipped = skipped_tables.iter().any(|item| {
        item.get("reason").and_then(Value::as_str) == Some("default_lean_continue_audit")
    });
    write_json_pretty(
        &output_dir.join("export_status.json"),
        &serde_json::json!({
            "schema": "smalltalk.continue_output.export_status.v1",
            "updatedAtMs": now_millis(),
            "status": status,
            "stage": stage,
            "decisionId": result.decision_id,
            "source": result.source,
            "model": result.model,
            "responseId": result.response_id,
            "criticalArtifacts": {
                "request": "request/get_continue_decision_request.json",
                "inferenceSummary": "inference/summary.json",
                "selectedCandidate": "continue/candidates/selected_candidate.json",
                "finalDecision": "final/continue_decision_result.json",
                "handoff": "final/handoff.json",
                "workTruth": "decision/work-truth.json",
                "currentSurfaceResolution": "decision/current_surface_resolution.json",
                "evidenceFreshnessLedger": "decision/evidence_freshness_ledger.json",
                "surfaceEnrichmentAttempts": "decision/surface-enrichment-attempts.json",
                "surfaceSnapshots": "decision/surface-snapshots.json",
                "taskTurnEvidence": "decision/task-turn-evidence.json",
                "currentTaskTurn": "decision/current-task-turn.json",
                "enrichedCurrentFocus": "decision/enriched-current-focus.json",
                "weakSurfaceCandidateGates": "decision/weak-surface-candidate-gates.json"
            },
            "rawArtifacts": {
                "database": "raw/smalltalk-capture.sqlite",
                "schema": "raw/schema.sql",
                "tables": "raw/tables/",
                "captureFrames": "capture/frames/"
            },
            "counts": {
                "warnings": warnings.len(),
                "rawErrors": raw_errors.len(),
                "skippedTables": skipped_tables.len(),
                "files": stats.file_count,
                "bytes": stats.byte_size
            },
            "rawExportStatus": if lean_raw_skipped {
                "skipped_default_lean_audit"
            } else if raw_errors.is_empty() {
                "ok_or_pending"
            } else {
                "errors_recorded"
            },
        }),
    )
}

fn write_continue_output_manifest(
    output_dir: &Path,
    generated_at: i64,
    folder_name: &str,
    plan: &ContinueOutputAuditPlan,
    effective_mode: &str,
    result: &crate::continuation::ContinueDecisionResult,
    raw_table_manifest: &[Value],
    frame_manifests: &[Value],
    layer_manifest: &[Value],
    candidate_manifest: &[Value],
    inference_manifest: &[Value],
    warnings: &[ExportWarning],
    raw_errors: &[Value],
    skipped_tables: &[Value],
) -> Result<(), String> {
    let file_index = collect_relative_file_index(output_dir).unwrap_or_default();
    let stats = directory_stats(output_dir).unwrap_or(ExportStats {
        file_count: 0,
        byte_size: 0,
    });
    let file_counts = continue_audit_file_counts(output_dir, &file_index);
    let row_counts = continue_audit_row_counts(raw_table_manifest);
    let export_status = if !raw_errors.is_empty() {
        "complete_with_warnings"
    } else if skipped_tables.is_empty() {
        "complete"
    } else {
        "partial_missing_optional_files"
    };
    let decision_summary = serde_json::json!({
        "mode": result.mode,
        "source": result.source,
        "validationStatus": result.validation_status,
        "cacheHit": result.cache_hit,
        "confidence": result.confidence,
        "confidenceLabel": result.confidence_label,
        "continueOutputMode": result.continue_output_mode,
    });
    let entrypoints = serde_json::json!({
        "explainMd": "explain.md",
        "decisionTrace": "decision/decision_trace.json",
        "finalDecision": "decision/final_decision.json",
        "workTruth": "decision/work-truth.json",
        "currentSurfaceResolution": "decision/current_surface_resolution.json",
        "evidenceFreshnessLedger": "decision/evidence_freshness_ledger.json",
        "surfaceEnrichmentAttempts": "decision/surface-enrichment-attempts.json",
        "surfaceSnapshots": "decision/surface-snapshots.json",
        "taskTurnEvidence": "decision/task-turn-evidence.json",
        "currentTaskTurn": "decision/current-task-turn.json",
        "enrichedCurrentFocus": "decision/enriched-current-focus.json",
        "weakSurfaceCandidateGates": "decision/weak-surface-candidate-gates.json",
        "legacyFinalDecision": "final/continue_decision_result.json",
        "evidenceClosure": "evidence/evidence_closure.json",
        "candidateScores": "decision/candidates.json",
        "modelValidation": "model/validation.json",
        "cacheDecision": "cache/cache_decision.json",
        "copyGate": "decision/copy_gate.json",
        "rawTableIndex": "raw/table_index.json"
    });
    let legacy_counts = serde_json::json!({
        "rawTables": raw_table_manifest.len(),
        "frames": frame_manifests.len(),
        "continueLayerTables": layer_manifest.len(),
        "candidateTables": candidate_manifest.len(),
        "inferenceEvents": inference_manifest.len(),
        "warnings": warnings.len(),
        "rawErrors": raw_errors.len(),
        "skippedTables": skipped_tables.len(),
        "filesBeforeManifest": file_index.len(),
    });
    let manifest_paths = serde_json::json!({
        "status": "export_status.json",
        "diskStatus": "disk_status.json",
        "request": "request/get_continue_decision_request.json",
        "rawDatabase": "raw/smalltalk-capture.sqlite",
        "schema": "raw/schema.sql",
        "rawTables": raw_table_manifest,
        "rawTableIndex": "raw/table_index.json",
        "rawErrors": "raw/export_errors.json",
        "skippedTables": "raw/skipped_tables.json",
        "captureFrames": frame_manifests,
        "selectedEvidenceFrames": "evidence/frames/",
        "evidenceClosure": "evidence/evidence_closure.json",
        "decisionTrace": "decision/decision_trace.json",
        "workTruth": "decision/work-truth.json",
        "continueLayers": layer_manifest,
        "continueCandidates": candidate_manifest,
        "selectedCandidate": "continue/candidates/selected_candidate.json",
        "canonicalCandidates": "decision/candidates.json",
        "cacheDecision": "cache/cache_decision.json",
        "model": "model/",
        "copyGate": "decision/copy_gate.json",
        "surfaceEnrichmentAttempts": "decision/surface-enrichment-attempts.json",
        "surfaceSnapshots": "decision/surface-snapshots.json",
        "taskTurnEvidence": "decision/task-turn-evidence.json",
        "currentTaskTurn": "decision/current-task-turn.json",
        "enrichedCurrentFocus": "decision/enriched-current-focus.json",
        "weakSurfaceCandidateGates": "decision/weak-surface-candidate-gates.json",
        "auditIntegrity": "audit_integrity.json",
        "inference": inference_manifest,
        "finalDecision": "final/continue_decision_result.json",
        "handoff": "final/handoff.json",
        "explanation": "explain.md",
        "warnings": "export_warnings.json",
        "fileIndex": file_index,
    });
    let stats_before_manifest = serde_json::json!({
        "fileCount": stats.file_count,
        "byteSize": stats.byte_size,
    });
    let notes = serde_json::json!([
        "This is a lean local developer audit focused on decision proof, selected evidence, model/cache/copy-gate behavior, and engine quality.",
        "Full SQLite snapshots, full raw table dumps, and all-frame capture exports are disabled by default because they duplicate the accumulated local capture database and are not useful as LLM-readable evidence.",
        "This audit is generated private developer output and must not be committed or uploaded accidentally.",
        "Use SMALLTALK_CONTINUE_AUDIT_FULL_RAW=1 or a full_raw effective mode only when an archival raw database/table dump is explicitly needed.",
        "Inference request bodies do not include API keys or authorization headers.",
        "The final Continue answer is in final/continue_decision_result.json and final/handoff.json."
    ]);
    write_json_pretty(
        &output_dir.join("manifest.json"),
        &serde_json::json!({
            "schema": "smalltalk.continue_audit_manifest.v2",
            "legacySchema": "smalltalk.continue_output.full_audit.v1",
            "generatedAtMs": generated_at,
            "updatedAtMs": now_millis(),
            "auditId": format!("continue-audit-{}", generated_at),
            "decisionId": result.decision_id,
            "cacheHit": result.cache_hit,
            "source": result.source,
            "model": result.model,
            "responseId": result.response_id,
            "effectiveMode": effective_mode,
            "sessionLabel": &plan.session_label,
            "folderName": folder_name,
            "path": plan.final_dir.to_string_lossy(),
            "containsSensitiveLocalEvidence": true,
            "latestFrame": result.current_focus,
            "selectedWorkstream": result.selected_workstream,
            "returnTarget": result.resume_work_target.as_ref().or(result.return_target.as_ref()),
            "decisionSummary": decision_summary,
            "exportStatus": export_status,
            "fileCounts": file_counts,
            "rowCounts": row_counts,
            "integrity": serde_json::from_str::<Value>(
                &fs::read_to_string(output_dir.join("audit_integrity.json")).unwrap_or_default()
            ).unwrap_or(Value::Null),
            "entrypoints": entrypoints,
            "counts": legacy_counts,
            "manifest": manifest_paths,
            "statsBeforeManifest": stats_before_manifest,
            "notes": notes,
        }),
    )
}

fn continue_audit_file_counts(output_dir: &Path, file_index: &[String]) -> Value {
    let selected_frame_folders = fs::read_dir(output_dir.join("evidence").join("frames"))
        .map(|entries| {
            entries
                .filter_map(Result::ok)
                .filter(|entry| entry.path().is_dir())
                .count()
        })
        .unwrap_or(0);
    serde_json::json!({
        "totalFiles": file_index.len(),
        "selectedFrameFolders": selected_frame_folders,
        "imagesWritten": file_index
            .iter()
            .filter(|path| path.contains("/images/")
                && (path.ends_with(".png") || path.ends_with(".jpg") || path.ends_with(".jpeg")))
            .count(),
        "jsonFiles": file_index.iter().filter(|path| path.ends_with(".json")).count(),
        "markdownFiles": file_index.iter().filter(|path| path.ends_with(".md")).count(),
        "rawTableFiles": file_index
            .iter()
            .filter(|path| path.starts_with("raw/tables/") && path.ends_with(".ndjson"))
            .count(),
        "sqliteSnapshots": file_index
            .iter()
            .filter(|path| path.ends_with(".sqlite"))
            .count(),
    })
}

fn continue_audit_row_counts(raw_table_manifest: &[Value]) -> Value {
    let mut raw_tables = serde_json::Map::new();
    for table in raw_table_manifest {
        if let Some(name) = table.get("table").and_then(Value::as_str) {
            raw_tables.insert(
                name.to_string(),
                table
                    .get("rowCount")
                    .or_else(|| table.get("rows_written"))
                    .cloned()
                    .unwrap_or(Value::Null),
            );
        }
    }
    serde_json::json!({ "rawTables": raw_tables })
}

fn continue_candidates_audit_json(
    result: &crate::continuation::ContinueDecisionResult,
    selected_candidate: &Value,
) -> Value {
    let selected_id = selected_candidate
        .get("id")
        .and_then(Value::as_str)
        .map(str::to_string)
        .or_else(|| {
            result
                .alternatives
                .iter()
                .find(|candidate| {
                    result
                        .return_target
                        .as_ref()
                        .and_then(|target| target.fallback_frame_id.as_ref())
                        == candidate.evidence_frame_id.as_ref()
                })
                .map(|candidate| candidate.candidate_id.clone())
        });
    let alternatives = result
        .alternatives
        .iter()
        .map(|candidate| {
            let score_after_feedback_gate = if candidate.eligible_for_primary_selection {
                Value::from(candidate.score)
            } else {
                Value::Null
            };
            serde_json::json!({
                "candidate_id": candidate.candidate_id,
                "workstream_id": candidate.workstream_id,
                "target_artifact_id": candidate.target_artifact_id,
                "feedback_target_keys": continue_candidate_feedback_target_keys(
                    candidate.candidate_id.as_str(),
                    candidate.workstream_id.as_str(),
                    candidate.target_artifact_id.as_deref(),
                ),
                "candidate_kind": candidate.candidate_kind,
                "evidence_frame_id": candidate.evidence_frame_id,
                "supporting_episode_id": candidate.supporting_episode_id,
                "last_meaningful_action_id": candidate.last_meaningful_action_id,
                "raw_score_before_caps": candidate.pre_cap_score,
                "score_after_caps": candidate.score,
                "final_score": candidate.score,
                "feedback_suppression_state": candidate.feedback_suppression_state,
                "feedback_negative_weight_since_reconfirmation": candidate.feedback_negative_weight,
                "feedback_last_negative_ms": candidate.feedback_last_negative_ms,
                "feedback_last_positive_ms": Value::Null,
                "feedback_last_reconfirming_evidence_ms": candidate.feedback_last_reconfirming_evidence_ms,
                "feedback_reason_codes": candidate.feedback_reason_codes,
                "primary_eligible_after_feedback": candidate.eligible_for_primary_selection,
                "public_alternative_eligible_after_feedback": candidate.public_alternative_eligible_after_feedback,
                "score_before_feedback_gate": candidate.pre_cap_score,
                "score_after_feedback_gate": score_after_feedback_gate,
                "score_components": {
                    "actionability_score": candidate.components.actionability,
                    "primary_target_score": candidate.components.primary_target,
                    "unresolved_score": candidate.components.unresolved_state,
                    "branch_origin_score": candidate.components.branch_origin,
                    "evidence_quality_score": candidate.components.evidence_quality,
                    "recency_score": candidate.components.recency,
                    "openability_score": candidate.components.openability,
                    "privacy_safety_score": candidate.components.privacy_safety,
                    "feedback_prior_score": candidate.components.feedback_prior,
                    "feedback_suppression_state": candidate.feedback_suppression_state.clone(),
                    "feedback_negative_weight": candidate.feedback_negative_weight,
                    "feedback_positive_weight_after_last_negative": candidate.feedback_positive_weight_after_last_negative,
                    "feedback_last_negative_ms": candidate.feedback_last_negative_ms,
                    "feedback_last_reconfirming_evidence_ms": candidate.feedback_last_reconfirming_evidence_ms,
                    "feedback_score_cap": candidate.feedback_score_cap,
                    "feedback_reason_codes": candidate.feedback_reason_codes.clone(),
                },
                "score_caps_applied": candidate.score_caps_applied,
                "demotions_applied": candidate.selection_demotion_reason.as_ref().map(|reason| {
                    vec![serde_json::json!({ "reason": reason })]
                }).unwrap_or_default(),
                "missing_evidence": candidate.missing_evidence,
                "warnings": candidate.risk_flags,
                "local_reason": candidate.reason,
                "eligible_for_primary_selection": candidate.eligible_for_primary_selection,
                "why_not_selected": if Some(candidate.candidate_id.as_str()) == selected_id.as_deref() {
                    Value::Null
                } else if !candidate.eligible_for_primary_selection {
                    Value::String(candidate.selection_demotion_reason.clone().unwrap_or_else(|| "not_eligible_for_primary_selection".to_string()))
                } else {
                    Value::String("lower_ranked_after_scoring_or_gate".to_string())
                },
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "schema": "smalltalk.continue_audit_candidates.v1",
        "selected_candidate_id": selected_id,
        "generated_candidates": result.generated_candidates,
        "feedback_policy_version": result.feedback_policy_version,
        "feedback_suppressed_candidate_count": result.feedback_suppressed_candidate_count,
        "feedback_score_capped_candidate_count": result.feedback_score_capped_candidate_count,
        "eligible_candidate_count_after_feedback_gate": result.eligible_candidate_count_after_feedback_gate,
        "model_candidate_count_before_feedback_filter": result.model_candidate_count_before_feedback_filter,
        "model_candidate_count_after_feedback_filter": result.model_candidate_count_after_feedback_filter,
        "selected_candidate_row": selected_candidate,
        "alternatives": alternatives,
    })
}

fn continue_candidate_feedback_target_keys(
    candidate_id: &str,
    workstream_id: &str,
    target_artifact_id: Option<&str>,
) -> Vec<String> {
    let mut keys = vec![
        format!("Candidate:{}", candidate_id),
        format!("Workstream:{}", workstream_id),
    ];
    if let Some(target_artifact_id) = target_artifact_id.filter(|value| !value.trim().is_empty()) {
        keys.push(format!("TargetArtifact:{}", target_artifact_id));
    }
    keys
}

fn continue_surface_enrichment_attempts_audit_json(
    conn: &Connection,
    result: &crate::continuation::ContinueDecisionResult,
) -> Result<Value, String> {
    if !table_exists_in_capture(conn, "continue_surface_enrichment_attempts")? {
        return Ok(serde_json::json!({
            "schema": "smalltalk.continue_audit_surface_enrichment_attempts.v1",
            "available": false,
            "rows": []
        }));
    }
    let decision_ms =
        continue_decision_requested_at_ms(conn, &result.decision_id)?.unwrap_or_else(now_millis);
    let since_ms = decision_ms.saturating_sub(45 * 60 * 1000);
    let rows = query_json_rows_with_params(
        conn,
        "SELECT *
         FROM continue_surface_enrichment_attempts
         WHERE observed_at_ms >= ?1
         ORDER BY observed_at_ms DESC, created_at_ms DESC
         LIMIT 40",
        &[&since_ms],
    )?;
    Ok(serde_json::json!({
        "schema": "smalltalk.continue_audit_surface_enrichment_attempts.v1",
        "available": true,
        "decisionId": result.decision_id,
        "sinceMs": since_ms,
        "rowCount": rows.len(),
        "rows": rows
    }))
}

