fn ensure_capture_db_empty(conn: &Connection) -> Result<(), String> {
    let frames = row_count(conn, "frames")?;
    let ocr = row_count(conn, "ocr_text")?;
    let fts = row_count(conn, "frames_fts")?;
    if frames == 0 && ocr == 0 && fts == 0 {
        Ok(())
    } else {
        Err(format!(
            "capture store was not fully cleared: frames={}, ocr_text={}, frames_fts={}",
            frames, ocr, fts
        ))
    }
}

fn row_count(conn: &Connection, table: &str) -> Result<i64, String> {
    conn.query_row(&format!("SELECT COUNT(*) FROM {}", table), [], |row| {
        row.get(0)
    })
    .map_err(to_string)
}

fn replace_capture_db(paths: &CapturePaths) -> Result<(), String> {
    invalidate_database_generation(&paths.db_path);
    drop_capture_db_files(&paths.db_path)?;
    let conn = open_db_at_path(&paths.db_path, true)?;
    init_db(&conn)?;
    register_initialized_database(&paths.db_path)?;
    ensure_capture_db_empty(&conn)
}

fn drop_capture_db_files(db_path: &Path) -> Result<(), String> {
    for path in capture_db_files(db_path) {
        if path.exists() {
            fs::remove_file(&path).map_err(to_string)?;
        }
    }
    Ok(())
}

fn capture_db_files(db_path: &Path) -> Vec<PathBuf> {
    let db = db_path.to_string_lossy();
    vec![
        db_path.to_path_buf(),
        PathBuf::from(format!("{}-wal", db)),
        PathBuf::from(format!("{}-shm", db)),
    ]
}

fn clear_snapshot_dir(snapshot_dir: &Path) -> Result<(), String> {
    clear_directory_contents(snapshot_dir)
}

fn clear_project_output_dir() -> Result<(), String> {
    clear_directory_contents(&project_output_root()?)
}

fn clear_project_resume_query_dir() -> Result<(), String> {
    clear_directory_contents(&project_resume_query_root()?)
}

fn clear_project_continue_outputs_dir() -> Result<(), String> {
    clear_directory_contents(&project_continue_outputs_root()?)
}

fn clear_directory_contents(dir: &Path) -> Result<(), String> {
    if dir.exists() {
        for entry in fs::read_dir(dir).map_err(to_string)? {
            let entry = entry.map_err(to_string)?;
            let path = entry.path();
            let metadata = fs::symlink_metadata(&path).map_err(to_string)?;
            if metadata.is_dir() {
                fs::remove_dir_all(&path).map_err(to_string)?;
            } else {
                fs::remove_file(&path).map_err(to_string)?;
            }
        }
    }
    fs::create_dir_all(dir).map_err(to_string)
}

fn open_db(app: &AppHandle) -> Result<Connection, String> {
    let paths = capture_paths(app)?;
    fs::create_dir_all(&paths.root_dir).map_err(to_string)?;
    ensure_database_initialized(&paths)?;
    open_db_at_path(&paths.db_path, true)
}

fn database_lifecycle() -> &'static Mutex<DatabaseLifecycle> {
    DATABASE_LIFECYCLE.get_or_init(|| Mutex::new(DatabaseLifecycle::default()))
}

fn database_file_identity(path: &Path) -> Result<Option<DatabaseFileIdentity>, String> {
    let metadata = match fs::metadata(path) {
        Ok(metadata) => metadata,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(error) => return Err(error.to_string()),
    };
    #[cfg(unix)]
    {
        use std::os::unix::fs::MetadataExt;
        Ok(Some(DatabaseFileIdentity {
            device: metadata.dev(),
            inode: metadata.ino(),
        }))
    }
    #[cfg(not(unix))]
    {
        Ok(Some(DatabaseFileIdentity {
            device: 0,
            inode: metadata.len(),
        }))
    }
}

fn ensure_database_initialized(paths: &CapturePaths) -> Result<(), String> {
    fs::create_dir_all(&paths.root_dir).map_err(to_string)?;
    let identity = database_file_identity(&paths.db_path)?;
    let mut lifecycle = database_lifecycle()
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner());
    if identity.is_some_and(|identity| {
        lifecycle
            .initialized
            .get(&paths.db_path)
            .is_some_and(|entry| entry.identity == identity)
    }) {
        return Ok(());
    }

    // Initialization is serialized only at the rare startup/replacement
    // boundary. Ordinary connections never execute schema discovery or DDL.
    let conn = open_db_at_path(&paths.db_path, true)?;
    init_db(&conn)?;
    SCHEMA_INITIALIZATION_COUNT.fetch_add(1, Ordering::Relaxed);
    MIGRATION_EXECUTION_COUNT.fetch_add(1, Ordering::Relaxed);
    let initialized_identity = database_file_identity(&paths.db_path)?
        .ok_or_else(|| "database initialization did not create a database file".to_string())?;
    lifecycle.next_generation = lifecycle.next_generation.saturating_add(1);
    let generation = lifecycle.next_generation;
    lifecycle.initialized.insert(
        paths.db_path.clone(),
        InitializedDatabase {
            generation,
            identity: initialized_identity,
        },
    );
    Ok(())
}

fn register_initialized_database(path: &Path) -> Result<(), String> {
    let identity = database_file_identity(path)?
        .ok_or_else(|| "initialized database file is missing".to_string())?;
    let mut lifecycle = database_lifecycle()
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner());
    lifecycle.next_generation = lifecycle.next_generation.saturating_add(1);
    let generation = lifecycle.next_generation;
    lifecycle.initialized.insert(
        path.to_path_buf(),
        InitializedDatabase {
            generation,
            identity,
        },
    );
    SCHEMA_INITIALIZATION_COUNT.fetch_add(1, Ordering::Relaxed);
    MIGRATION_EXECUTION_COUNT.fetch_add(1, Ordering::Relaxed);
    Ok(())
}

fn invalidate_database_generation(path: &Path) {
    database_lifecycle()
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner())
        .initialized
        .remove(path);
}

fn current_database_generation() -> u64 {
    database_lifecycle()
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner())
        .initialized
        .values()
        .map(|entry| entry.generation)
        .max()
        .unwrap_or(0)
}

fn open_db_at_path(db_path: &Path, writable: bool) -> Result<Connection, String> {
    let conn = if writable {
        Connection::open(db_path).map_err(to_string)?
    } else {
        Connection::open_with_flags(db_path, OpenFlags::SQLITE_OPEN_READ_ONLY).map_err(to_string)?
    };
    configure_db_connection(&conn, writable)?;
    Ok(conn)
}

fn open_readonly_db(app: &AppHandle) -> Result<Connection, String> {
    let paths = capture_paths(app)?;
    open_db_at_path(&paths.db_path, false)
}

fn configure_db_connection(conn: &Connection, writable: bool) -> Result<(), String> {
    let busy_timeout = if writable {
        SQLITE_WRITE_BUSY_TIMEOUT
    } else {
        SQLITE_READ_BUSY_TIMEOUT
    };
    conn.busy_timeout(busy_timeout).map_err(to_string)?;
    let _ = conn.pragma_update(None, "busy_timeout", busy_timeout.as_millis() as i64);
    if writable {
        let _ = conn.pragma_update(None, "journal_mode", "WAL");
        let _ = conn.pragma_update(None, "synchronous", "NORMAL");
    }
    Ok(())
}

pub(crate) fn init_db(conn: &Connection) -> Result<(), String> {
    conn.execute_batch(
        "
        CREATE TABLE IF NOT EXISTS frames (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          session_id TEXT,
          captured_at INTEGER NOT NULL,
          snapshot_path TEXT NOT NULL,
          app_name TEXT,
          window_name TEXT,
          browser_url TEXT,
          document_path TEXT,
          focused INTEGER NOT NULL DEFAULT 1,
          capture_trigger TEXT NOT NULL,
          text_source TEXT,
          accessibility_text TEXT,
          accessibility_tree_json TEXT,
          full_text TEXT,
          content_hash TEXT,
          image_hash TEXT,
          created_at INTEGER NOT NULL
        );

        CREATE TABLE IF NOT EXISTS ocr_text (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          frame_id INTEGER NOT NULL REFERENCES frames(id) ON DELETE CASCADE,
          text TEXT,
          text_json TEXT,
          ocr_engine TEXT
        );

        CREATE VIRTUAL TABLE IF NOT EXISTS frames_fts
        USING fts5(full_text, app_name, window_name, browser_url, document_path);

        CREATE TRIGGER IF NOT EXISTS frames_ai AFTER INSERT ON frames BEGIN
          INSERT INTO frames_fts(rowid, full_text, app_name, window_name, browser_url, document_path)
          VALUES (new.id, new.full_text, new.app_name, new.window_name, new.browser_url, new.document_path);
        END;

        CREATE TRIGGER IF NOT EXISTS frames_ad AFTER DELETE ON frames BEGIN
          DELETE FROM frames_fts WHERE rowid = old.id;
        END;

        CREATE INDEX IF NOT EXISTS idx_frames_captured_at ON frames(captured_at DESC);
        CREATE INDEX IF NOT EXISTS idx_frames_session ON frames(session_id, captured_at DESC);
        CREATE INDEX IF NOT EXISTS idx_ocr_text_frame_id ON ocr_text(frame_id);

        CREATE TABLE IF NOT EXISTS local_memory_maintenance (
          key TEXT PRIMARY KEY,
          value TEXT NOT NULL,
          updated_at_ms INTEGER NOT NULL
        );

        CREATE TABLE IF NOT EXISTS capture_sessions (
          id TEXT PRIMARY KEY,
          sequence INTEGER NOT NULL DEFAULT 0,
          started_at_ms INTEGER NOT NULL,
          stopped_at_ms INTEGER,
          status TEXT NOT NULL,
          export_path TEXT,
          frame_count INTEGER NOT NULL DEFAULT 0,
          event_count INTEGER NOT NULL DEFAULT 0,
          transition_count INTEGER NOT NULL DEFAULT 0,
          content_unit_count INTEGER NOT NULL DEFAULT 0,
          summary_json TEXT,
          created_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_capture_sessions_started
          ON capture_sessions(started_at_ms DESC);

        CREATE TABLE IF NOT EXISTS ui_events (
          id TEXT PRIMARY KEY,
          session_id TEXT,
          ts_ms INTEGER NOT NULL,
          event_type TEXT NOT NULL,
          app_pid INTEGER,
          app_bundle_id TEXT,
          app_name TEXT,
          window_id INTEGER,
          window_title TEXT,
          x REAL,
          y REAL,
          button TEXT,
          scroll_dx REAL,
          scroll_dy REAL,
          key_category TEXT,
          modifier_flags TEXT,
          is_repeat INTEGER,
          payload_json TEXT,
          created_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_ui_events_session_ts ON ui_events(session_id, ts_ms);
        CREATE INDEX IF NOT EXISTS idx_ui_events_ts ON ui_events(ts_ms);
        CREATE INDEX IF NOT EXISTS idx_ui_events_type_ts ON ui_events(event_type, ts_ms);

        CREATE TABLE IF NOT EXISTS capture_triggers (
          id TEXT PRIMARY KEY,
          session_id TEXT,
          ts_ms INTEGER NOT NULL,
          trigger_type TEXT NOT NULL,
          caused_by_event_ids TEXT NOT NULL,
          settle_delay_ms INTEGER NOT NULL,
          rate_limited INTEGER DEFAULT 0,
          dedupe_policy TEXT NOT NULL,
          pre_frame_id TEXT,
          post_frame_id TEXT,
          status TEXT NOT NULL,
          error TEXT,
          caused_event_count INTEGER NOT NULL DEFAULT 0,
          omitted_event_count INTEGER NOT NULL DEFAULT 0,
          aggregation_json TEXT
        );
        CREATE INDEX IF NOT EXISTS idx_capture_triggers_session_ts
          ON capture_triggers(session_id, ts_ms);

        CREATE TABLE IF NOT EXISTS event_transitions (
          id TEXT PRIMARY KEY,
          session_id TEXT,
          trigger_id TEXT NOT NULL,
          primary_event_id TEXT,
          pre_frame_id TEXT,
          post_frame_id TEXT,
          ts_start_ms INTEGER NOT NULL,
          ts_end_ms INTEGER NOT NULL,
          transition_type TEXT,
          confidence REAL,
          summary TEXT,
          changed_region_json TEXT,
          FOREIGN KEY(trigger_id) REFERENCES capture_triggers(id)
        );
        CREATE INDEX IF NOT EXISTS idx_event_transitions_session_ts
          ON event_transitions(session_id, ts_start_ms);

        CREATE TABLE IF NOT EXISTS window_snapshots (
          id TEXT PRIMARY KEY,
          frame_id TEXT,
          ts_ms INTEGER NOT NULL,
          active_window_id INTEGER,
          active_app_pid INTEGER,
          active_app_bundle_id TEXT,
          screen_count INTEGER,
          raw_json TEXT
        );
        CREATE INDEX IF NOT EXISTS idx_window_snapshots_frame
          ON window_snapshots(frame_id);
        CREATE INDEX IF NOT EXISTS idx_window_snapshots_ts
          ON window_snapshots(ts_ms DESC, id DESC);

        CREATE TABLE IF NOT EXISTS windows (
          id TEXT PRIMARY KEY,
          window_snapshot_id TEXT NOT NULL,
          cg_window_id INTEGER,
          owner_pid INTEGER,
          owner_name TEXT,
          bundle_id TEXT,
          window_title TEXT,
          layer INTEGER,
          alpha REAL,
          is_onscreen INTEGER,
          is_active INTEGER,
          bounds_x REAL,
          bounds_y REAL,
          bounds_w REAL,
          bounds_h REAL,
          workspace INTEGER,
          raw_json TEXT,
          FOREIGN KEY(window_snapshot_id) REFERENCES window_snapshots(id)
        );
        CREATE INDEX IF NOT EXISTS idx_windows_snapshot
          ON windows(window_snapshot_id);

        CREATE TABLE IF NOT EXISTS ax_nodes (
          id TEXT PRIMARY KEY,
          frame_id TEXT NOT NULL,
          parent_id TEXT,
          app_pid INTEGER,
          window_id INTEGER,
          role TEXT,
          subrole TEXT,
          role_description TEXT,
          title TEXT,
          value TEXT,
          description TEXT,
          help TEXT,
          identifier TEXT,
          document TEXT,
          url TEXT,
          selected_text TEXT,
          selected_text_range_json TEXT,
          visible_character_range_json TEXT,
          number_of_characters INTEGER,
          focused INTEGER,
          enabled INTEGER,
          selected INTEGER,
          bounds_x REAL,
          bounds_y REAL,
          bounds_w REAL,
          bounds_h REAL,
          actions_json TEXT,
          children_count INTEGER,
          depth INTEGER,
          tree_order INTEGER,
          raw_json TEXT,
          FOREIGN KEY(frame_id) REFERENCES frames(id)
        );
        CREATE INDEX IF NOT EXISTS idx_ax_nodes_frame ON ax_nodes(frame_id);
        CREATE INDEX IF NOT EXISTS idx_ax_nodes_bounds ON ax_nodes(frame_id, bounds_x, bounds_y);

        CREATE TABLE IF NOT EXISTS ocr_spans (
          id TEXT PRIMARY KEY,
          frame_id TEXT NOT NULL,
          engine TEXT NOT NULL,
          text TEXT NOT NULL,
          confidence REAL,
          lang TEXT,
          block_index INTEGER,
          line_index INTEGER,
          word_index INTEGER,
          bounds_x REAL NOT NULL,
          bounds_y REAL NOT NULL,
          bounds_w REAL NOT NULL,
          bounds_h REAL NOT NULL,
          normalized_bounds_json TEXT,
          raw_json TEXT,
          source_scope TEXT,
          ownership_kind TEXT,
          ownership_confidence REAL,
          active_artifact_match_confidence REAL,
          owner_window_id INTEGER,
          owner_app_pid INTEGER,
          owner_bundle_id TEXT,
          owner_app_name TEXT,
          owner_window_title TEXT,
          coordinate_space TEXT,
          coordinate_transform_json TEXT,
          quality_flags_json TEXT,
          provenance_json TEXT,
          FOREIGN KEY(frame_id) REFERENCES frames(id)
        );
        CREATE INDEX IF NOT EXISTS idx_ocr_spans_frame ON ocr_spans(frame_id);

        CREATE TABLE IF NOT EXISTS content_units (
          id TEXT PRIMARY KEY,
          frame_id TEXT NOT NULL,
          window_id INTEGER,
          source TEXT NOT NULL,
          unit_type TEXT NOT NULL,
          text TEXT,
          text_hash TEXT,
          semantic_role TEXT,
          ax_node_id TEXT,
          ocr_span_ids TEXT,
          adapter_object_id TEXT,
          bounds_x REAL,
          bounds_y REAL,
          bounds_w REAL,
          bounds_h REAL,
          crop_path TEXT,
          visible_ratio REAL,
          center_distance REAL,
          confidence REAL,
          source_scope TEXT,
          ownership_kind TEXT,
          ownership_confidence REAL,
          active_artifact_match_confidence REAL,
          owner_window_id INTEGER,
          owner_bundle_id TEXT,
          quality_flags_json TEXT,
          provenance_json TEXT,
          source_order INTEGER,
          created_at_ms INTEGER NOT NULL,
          raw_json TEXT,
          FOREIGN KEY(frame_id) REFERENCES frames(id)
        );
        CREATE INDEX IF NOT EXISTS idx_content_units_frame ON content_units(frame_id);
        CREATE INDEX IF NOT EXISTS idx_content_units_text_hash ON content_units(text_hash);

        CREATE TABLE IF NOT EXISTS frame_diffs (
          id TEXT PRIMARY KEY,
          session_id TEXT,
          from_frame_id TEXT NOT NULL,
          to_frame_id TEXT NOT NULL,
          ts_ms INTEGER NOT NULL,
          same_app INTEGER,
          same_window INTEGER,
          visual_phash_distance REAL,
          changed_region_json TEXT,
          added_text_hashes TEXT,
          removed_text_hashes TEXT,
          stable_text_hashes TEXT,
          ax_tree_delta_json TEXT,
          ocr_delta_json TEXT,
          diff_type TEXT,
          confidence REAL,
          summary TEXT,
          FOREIGN KEY(from_frame_id) REFERENCES frames(id),
          FOREIGN KEY(to_frame_id) REFERENCES frames(id)
        );
        CREATE INDEX IF NOT EXISTS idx_frame_diffs_session
          ON frame_diffs(session_id);
        CREATE INDEX IF NOT EXISTS idx_frame_diffs_to_frame
          ON frame_diffs(to_frame_id);

        CREATE TABLE IF NOT EXISTS app_contexts (
          id TEXT PRIMARY KEY,
          frame_id TEXT NOT NULL,
          adapter_id TEXT NOT NULL,
          object_type TEXT NOT NULL,
          primary_id TEXT,
          title TEXT,
          url TEXT,
          file_path TEXT,
          repo_path TEXT,
          line_number INTEGER,
          selected_text TEXT,
          focused_object TEXT,
          confidence REAL,
          metadata_json TEXT,
          FOREIGN KEY(frame_id) REFERENCES frames(id)
        );
        CREATE INDEX IF NOT EXISTS idx_app_contexts_frame
          ON app_contexts(frame_id);

        CREATE TABLE IF NOT EXISTS clipboard_events (
          id TEXT PRIMARY KEY,
          session_id TEXT,
          ts_ms INTEGER NOT NULL,
          change_count INTEGER NOT NULL,
          content_type TEXT NOT NULL,
          text_hash TEXT,
          redacted_preview TEXT,
          byte_size INTEGER,
          source_frame_id TEXT,
          source_content_unit_id TEXT,
          target_frame_id TEXT,
          pasted_within_ms INTEGER,
          metadata_json TEXT
        );
        CREATE INDEX IF NOT EXISTS idx_clipboard_events_session
          ON clipboard_events(session_id);
        CREATE INDEX IF NOT EXISTS idx_clipboard_events_source_frame
          ON clipboard_events(source_frame_id);

        CREATE TABLE IF NOT EXISTS typing_bursts (
          id TEXT PRIMARY KEY,
          session_id TEXT,
          started_at_ms INTEGER NOT NULL,
          ended_at_ms INTEGER NOT NULL,
          app_pid INTEGER,
          app_bundle_id TEXT,
          app_name TEXT,
          window_id INTEGER,
          window_title TEXT,
          focused_ax_node_id TEXT,
          focused_content_unit_id TEXT,
          char_count INTEGER DEFAULT 0,
          backspace_count INTEGER DEFAULT 0,
          enter_count INTEGER DEFAULT 0,
          paste_count INTEGER DEFAULT 0,
          shortcut_count INTEGER DEFAULT 0,
          committed INTEGER DEFAULT 0,
          commit_signal TEXT,
          raw_text_captured INTEGER DEFAULT 0,
          text_hash TEXT,
          redacted_preview TEXT,
          pre_frame_id TEXT,
          post_frame_id TEXT,
          start_event_id TEXT,
          last_event_id TEXT,
          commit_event_id TEXT,
          capture_trigger_id TEXT,
          post_frame_association_source TEXT,
          post_frame_association_confidence REAL,
          post_frame_association_reasons_json TEXT,
          post_frame_associated_at_ms INTEGER
        );
        CREATE INDEX IF NOT EXISTS idx_typing_bursts_session
          ON typing_bursts(session_id);
        CREATE INDEX IF NOT EXISTS idx_typing_bursts_pre_frame
          ON typing_bursts(pre_frame_id);
        CREATE INDEX IF NOT EXISTS idx_typing_bursts_post_frame
          ON typing_bursts(post_frame_id);

        CREATE TABLE IF NOT EXISTS presence_samples (
          id TEXT PRIMARY KEY,
          session_id TEXT,
          ts_ms INTEGER NOT NULL,
          idle_seconds REAL,
          display_asleep INTEGER,
          screen_locked INTEGER,
          active_input_recently INTEGER,
          cursor_moved_recently INTEGER,
          frontmost_app_bundle_id TEXT
        );
        CREATE INDEX IF NOT EXISTS idx_presence_samples_session
          ON presence_samples(session_id);

        CREATE TABLE IF NOT EXISTS exclusion_rules (
          id TEXT PRIMARY KEY,
          rule_type TEXT NOT NULL,
          pattern TEXT NOT NULL,
          action TEXT NOT NULL,
          enabled INTEGER DEFAULT 1,
          origin TEXT NOT NULL DEFAULT 'user',
          created_at_ms INTEGER NOT NULL
        );

        CREATE TABLE IF NOT EXISTS sensitive_regions (
          id TEXT PRIMARY KEY,
          frame_id TEXT NOT NULL,
          region_type TEXT NOT NULL,
          bounds_x REAL,
          bounds_y REAL,
          bounds_w REAL,
          bounds_h REAL,
          source TEXT NOT NULL,
          confidence REAL,
          action_taken TEXT,
          rule_id TEXT,
          rule_origin TEXT,
          metadata_json TEXT
        );
        CREATE INDEX IF NOT EXISTS idx_sensitive_regions_frame
          ON sensitive_regions(frame_id);

        CREATE TABLE IF NOT EXISTS frame_text_resolutions (
          frame_id TEXT PRIMARY KEY,
          active_text TEXT,
          background_text TEXT,
          diagnostic_text TEXT,
          full_text_quality TEXT NOT NULL,
          quality_flags_json TEXT NOT NULL,
          resolution_json TEXT NOT NULL,
          active_content_hash TEXT,
          background_content_hash TEXT,
          created_at_ms INTEGER NOT NULL
        );

        CREATE TABLE IF NOT EXISTS frame_quality_warnings (
          id TEXT PRIMARY KEY,
          frame_id TEXT NOT NULL,
          warning_type TEXT NOT NULL,
          severity TEXT NOT NULL,
          message TEXT NOT NULL,
          evidence_json TEXT NOT NULL,
          created_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_frame_quality_warnings_frame
          ON frame_quality_warnings(frame_id);

        CREATE TABLE IF NOT EXISTS ai_export_audit (
          id TEXT PRIMARY KEY,
          created_at_ms INTEGER NOT NULL,
          export_type TEXT NOT NULL,
          lookback_start_ms INTEGER,
          lookback_end_ms INTEGER,
          input_frame_count INTEGER NOT NULL,
          exported_frame_count INTEGER NOT NULL,
          excluded_frame_count INTEGER NOT NULL,
          masked_image_count INTEGER NOT NULL,
          redacted_text_count INTEGER NOT NULL,
          warnings_json TEXT NOT NULL
        );

        CREATE TABLE IF NOT EXISTS embeddings (
          id TEXT PRIMARY KEY,
          object_type TEXT NOT NULL,
          object_id TEXT NOT NULL,
          model TEXT NOT NULL,
          dims INTEGER NOT NULL,
          vector BLOB NOT NULL,
          text_hash TEXT,
          created_at_ms INTEGER NOT NULL
        );
        CREATE INDEX IF NOT EXISTS idx_embeddings_object ON embeddings(object_type, object_id);

        CREATE TABLE IF NOT EXISTS episodes (
          id TEXT PRIMARY KEY,
          session_id TEXT,
          start_frame_id TEXT,
          end_frame_id TEXT,
          started_at_ms INTEGER NOT NULL,
          ended_at_ms INTEGER,
          status TEXT NOT NULL,
          role_guess TEXT,
          app TEXT,
          surface_type TEXT,
          title TEXT,
          primary_goal TEXT,
          current_surface_type TEXT,
          confidence REAL,
          summary TEXT,
          quality_flags_json TEXT,
          metadata_json TEXT
        );
        ",
    )
    .map_err(to_string)?;

    ensure_frame_columns(conn)?;
    ensure_ax_node_columns(conn)?;
    ensure_ocr_span_columns(conn)?;
    ensure_content_unit_columns(conn)?;
    ensure_frame_text_resolution_table(conn)?;
    ensure_session_columns(conn)?;
    ensure_typing_burst_columns(conn)?;
    ensure_episode_columns(conn)?;
    ensure_privacy_columns(conn)?;
    crate::continuation::ensure_continue_schema(conn)?;
    ensure_default_exclusion_rules(conn)?;
    migrate_browser_privacy_policy_v1(conn)?;
    migrate_manual_continue_capture_integrity_v1(conn)?;
    Ok(())
}

fn ensure_frame_columns(conn: &Connection) -> Result<(), String> {
    let columns = table_columns(conn, "frames")?;
    let additions = [
        ("session_id", "TEXT"),
        ("capture_provider", "TEXT"),
        ("scope", "TEXT"),
        ("display_id", "TEXT"),
        ("window_id", "INTEGER"),
        ("app_pid", "INTEGER"),
        ("app_bundle_id", "TEXT"),
        ("screen_scale", "REAL"),
        ("pixel_width", "INTEGER"),
        ("pixel_height", "INTEGER"),
        ("full_screenshot_path", "TEXT"),
        ("active_window_crop_path", "TEXT"),
        ("active_element_crop_path", "TEXT"),
        ("phash", "TEXT"),
        ("privacy_status", "TEXT DEFAULT 'normal'"),
        ("capture_trigger_id", "TEXT"),
        ("previous_frame_id", "TEXT"),
        ("sck_display_id", "TEXT"),
        ("sck_window_id", "INTEGER"),
        ("sck_owning_bundle_id", "TEXT"),
        ("sck_filter_summary_json", "TEXT"),
        ("sck_configuration_summary_json", "TEXT"),
        ("sck_frame_metadata_json", "TEXT"),
        ("sck_capture_mode", "TEXT"),
        ("sck_audio_policy", "TEXT"),
        ("active_window_capture_provider", "TEXT"),
    ];

    for (name, definition) in additions {
        if !columns.contains(name) {
            conn.execute(
                &format!("ALTER TABLE frames ADD COLUMN {} {}", name, definition),
                [],
            )
            .map_err(to_string)?;
        }
    }

    Ok(())
}

