    #[test]
    fn manual_continue_resolves_unique_bundle_and_title_to_a_window_id() {
        let event = ManualContinueExternalEvent {
            ts_ms: 1_000,
            app_pid: Some(100),
            app_bundle_id: Some("net.imput.helium".to_string()),
            app_name: Some("Helium".to_string()),
            window_id: None,
            window_title: Some("Tool Annotations Charter - Helium".to_string()),
        };
        let snapshot = WindowSnapshotPayload {
            ts_ms: 1_100,
            active_window_id: Some(7),
            active_app_pid: None,
            active_app_bundle_id: Some(SMALLTALK_BUNDLE_ID.to_string()),
            screen_count: 1,
            windows: vec![
                WindowPayload {
                    cg_window_id: Some(42),
                    owner_pid: Some(100),
                    owner_name: Some("Helium".to_string()),
                    bundle_id: Some("net.imput.helium".to_string()),
                    window_title: Some("Tool Annotations Charter".to_string()),
                    layer: Some(0),
                    alpha: Some(1.0),
                    is_onscreen: Some(true),
                    is_active: false,
                    bounds: None,
                    workspace: None,
                    raw: HashMap::new(),
                },
                WindowPayload {
                    cg_window_id: Some(7),
                    owner_pid: Some(200),
                    owner_name: Some("Smalltalk".to_string()),
                    bundle_id: Some(SMALLTALK_BUNDLE_ID.to_string()),
                    window_title: Some("Smalltalk".to_string()),
                    layer: Some(0),
                    alpha: Some(1.0),
                    is_onscreen: Some(true),
                    is_active: true,
                    bounds: None,
                    workspace: None,
                    raw: HashMap::new(),
                },
            ],
        };
        assert_eq!(
            resolve_manual_continue_window_id(&event, Some(&snapshot)),
            Some(42)
        );

        let mut no_matching_window = snapshot.clone();
        no_matching_window.windows.clear();
        assert_eq!(
            resolve_manual_continue_window_id(&event, Some(&no_matching_window)),
            None
        );

        let mut ambiguous_windows = snapshot.clone();
        let mut second_match = ambiguous_windows.windows[0].clone();
        second_match.cg_window_id = Some(43);
        ambiguous_windows.windows.push(second_match);
        assert_eq!(
            resolve_manual_continue_window_id(&event, Some(&ambiguous_windows)),
            None
        );
    }

