    #[test]
    fn production_frame_insert_matches_schema_column_count() {
        let conn = Connection::open_in_memory().unwrap();
        init_db(&conn).unwrap();

        conn.execute(
            INSERT_FRAME_SQL,
            params![
                1_i64,
                "/tmp/smalltalk-frame.jpg",
                Some("App"),
                Some("Window"),
                Option::<String>::None,
                Option::<String>::None,
                true,
                "manual",
                "accessibility",
                Some("visible text"),
                Option::<String>::None,
                Some("visible text searchable"),
                Some("content-hash"),
                Some("image-hash"),
                1_i64,
                "screencapture_cli",
                "active_display",
                Some("main"),
                Option::<i64>::None,
                Some(123_i64),
                Some("com.example.App"),
                1.0_f64,
                Some(1440_i64),
                Some(900_i64),
                "/tmp/smalltalk-frame.jpg",
                Option::<String>::None,
                Option::<String>::None,
                Some("phash"),
                "normal",
                Some("trigger-1"),
                Option::<String>::None,
                Some("session-1"),
                Option::<String>::None,
                Option::<i64>::None,
                Option::<String>::None,
                Option::<String>::None,
                Option::<String>::None,
                Option::<String>::None,
                Option::<String>::None,
                Option::<String>::None,
            ],
        )
        .unwrap();

        let frames: i64 = conn
            .query_row("SELECT COUNT(*) FROM frames", [], |row| row.get(0))
            .unwrap();
        assert_eq!(frames, 1);
    }

    #[test]
    fn init_db_repairs_legacy_episode_schema_before_creating_indexes() {
        let conn = Connection::open_in_memory().unwrap();
        conn.execute_batch(
            "
            CREATE TABLE episodes (id TEXT PRIMARY KEY);
            CREATE TABLE episode_nodes (id TEXT PRIMARY KEY);
            CREATE TABLE episode_edges (id TEXT PRIMARY KEY);
            CREATE TABLE episode_evidence (id TEXT PRIMARY KEY);
            ",
        )
        .unwrap();

        init_db(&conn).unwrap();

        let episode_columns = table_columns(&conn, "episodes").unwrap();
        for column in [
            "session_id",
            "start_frame_id",
            "end_frame_id",
            "started_at_ms",
            "ended_at_ms",
            "status",
            "role_guess",
            "app",
            "surface_type",
            "title",
            "primary_goal",
            "current_surface_type",
            "confidence",
            "summary",
            "quality_flags_json",
            "metadata_json",
        ] {
            assert!(
                episode_columns.contains(column),
                "missing episodes.{column}"
            );
        }

        let evidence_columns = table_columns(&conn, "episode_evidence").unwrap();
        for column in [
            "episode_id",
            "frame_id",
            "evidence_type",
            "text",
            "image_ref",
            "score",
            "reason",
            "created_at_ms",
        ] {
            assert!(
                evidence_columns.contains(column),
                "missing episode_evidence.{column}"
            );
        }

        let index_count: i64 = conn
            .query_row(
                "SELECT COUNT(*)
                 FROM sqlite_master
                 WHERE type = 'index'
                   AND name IN (
                     'idx_episodes_session',
                     'idx_episode_evidence_episode',
                     'idx_episode_evidence_frame'
                   )",
                [],
                |row| row.get(0),
            )
            .unwrap();
        assert_eq!(index_count, 3);

        conn.execute(
            "INSERT INTO episodes (
                id, session_id, start_frame_id, end_frame_id, started_at_ms, ended_at_ms,
                status, role_guess, app, surface_type, title, primary_goal,
                current_surface_type, confidence, summary, quality_flags_json, metadata_json
             ) VALUES (
                'episode-1', 'session-1', '1', '2', 100, 200,
                'closed', 'origin', 'App', 'doc', 'Title', 'Goal',
                'doc', 0.9, 'Summary', '[]', '{}'
             )",
            [],
        )
        .unwrap();
        conn.execute(
            "INSERT INTO episode_evidence (
                id, episode_id, frame_id, evidence_type, text, image_ref, score, reason, created_at_ms
             ) VALUES (
                'evidence-1', 'episode-1', '1', 'text_snippet', 'Important text',
                NULL, 0.9, 'origin', 300
             )",
            [],
        )
        .unwrap();
    }

