        assert!(audit_dir.join("export_status.json").exists());
        assert!(audit_dir.join("disk_status.json").exists());
        assert!(audit_dir.join("raw/export_errors.json").exists());
        assert!(audit_dir.join("raw/skipped_tables.json").exists());
